// ── Context-aware specificity scorer ─────────────────────────────────────────
function scoreSpecificProducts(text) {
  if (!text || text.trim().length === 0) return { score: 0, label: "—", detail: "" };
  const t = text.trim().toLowerCase();
  const wordCount = t.split(/\s+/).filter(Boolean).length;

  // High-value commercial keywords
  const urgencyWords    = ["urgent","q1","q2","q3","q4","asap","immediately","deadline","replacing","replacement","budget approved","approved budget","tender","rfp","rfq"];
  const quantityWords   = ["units","unit","beds","sites","fleet","contract","licence","licenses"];
  const timelineWords   = ["months","weeks","year","2024","2025","2026","january","february","march","april","may","june","july","august","september","october","november","december"];
  const specificWords   = ["hl7","pacs","mri","ct","crm","erp","api","iso","ce mark","fda","gdpr","nhs framework","nhs supply","framework price","framework pricing","capex","opex"];
  const vagueWords      = ["something","maybe","not sure","possibly","interested","general","everything","whatever","anything","looking at"];

  const hasUrgency   = urgencyWords.some(w => t.includes(w));
  const hasQuantity  = quantityWords.some(w => t.includes(w));
  const hasTimeline  = timelineWords.some(w => t.includes(w));
  const hasSpecific  = specificWords.some(w => t.includes(w));
  const hasVague     = vagueWords.some(w => t.includes(w));

  // Penalise vague/generic answers
  if (hasVague && wordCount < 8) return { score: 1, label: "Too vague", detail: "Response too generic to score" };

  let pts = 0;
  let reasons = [];

  // Base: just wrote something meaningful
  if (wordCount >= 3)  { pts += 2; reasons.push("described a need"); }
  if (wordCount >= 8)  { pts += 1; reasons.push("detailed description"); }
  if (wordCount >= 15) { pts += 1; reasons.push("comprehensive detail"); }

  // Scoring bonuses
  if (hasSpecific)  { pts += 2; reasons.push("technical/compliance specifics"); }
  if (hasQuantity)  { pts += 1; reasons.push("quantity or scale mentioned"); }
  if (hasTimeline)  { pts += 1; reasons.push("timeline reference"); }
  if (hasUrgency)   { pts += 2; reasons.push("urgency signal"); }

  pts = Math.min(pts, 9);

  const label = pts >= 8 ? "Very specific" : pts >= 6 ? "Specific" : pts >= 4 ? "Moderate" : pts >= 2 ? "General" : "Minimal";
  const detail = reasons.length > 0 ? reasons.slice(0,2).join(" · ") : "basic description";

  return { score: pts, label, detail };
}

// ── Context-aware conversation notes scorer (staff app) ───────────────────────
// Same engine as registration but tuned for on-site conversation context.
// Staff notes carry HIGHER weight than registration text because they describe
// an actual conversation, not a form response.
function scoreConversationNotes(text) {
  if (!text || text.trim().length === 0) return { score: 0, label: "—", detail: "", color: "#94A3B8" };
  const t = text.trim().toLowerCase();
  const words = t.split(/[\s,\.]+/).filter(Boolean);
  const wordCount = words.length;

  // On-site buying signals — higher weight than registration
  const buyingSignals   = ["budget","approved","confirmed","sign off","signoff","purchase order","po","tender","rfp","rfq","decision","shortlist","shortlisted","next step","follow up","follow-up","proposal","demo","pilot","trial","contract","procurement","buy","buying","purchase","replace","replacing","upgrade","replacement"];
  const timelineSignals = ["q1","q2","q3","q4","this quarter","next quarter","january","february","march","april","may","june","july","august","september","october","november","december","months","weeks","end of year","fiscal","fy","asap","urgent","immediately","before","deadline","by"];
  const quantitySignals = ["units","unit","seats","licences","licenses","sites","locations","beds","devices","systems","fleet","contract","scale","enterprise","global","nationwide","regional"];
  const technicalSignals = ["integrate","integration","api","hl7","fhir","pacs","erp","crm","sso","gdpr","iso","ce","fda","hipaa","compliance","certified","certification","compatible","interoperable","cloud","on-premise","saas"];
  const competitorSignals = ["currently using","already have","switching from","replacing","competitor","alternative","comparing","vs ","versus","better than","different from","instead of"];
  const authoritySignals  = ["i decide","my decision","i can approve","i sign","our cfo","our board","sign off","budget holder","my team","my department","we are evaluating","we need","we want","we have approved","we have budget"];
  const negativeSignals   = ["just looking","no budget","not this year","maybe next","no decision","not sure","unclear","need to check","will discuss","let me think","not my decision","someone else","my manager","not now","too expensive","can't afford"];

  const hasBuying     = buyingSignals.some(w => t.includes(w));
  const hasTimeline   = timelineSignals.some(w => t.includes(w));
  const hasQuantity   = quantitySignals.some(w => t.includes(w));
  const hasTechnical  = technicalSignals.some(w => t.includes(w));
  const hasCompetitor = competitorSignals.some(w => t.includes(w));
  const hasAuthority  = authoritySignals.some(w => t.includes(w));
  const hasNegative   = negativeSignals.some(w => t.includes(w));

  // If negative signals dominate a short note — penalise
  if (hasNegative && !hasBuying && wordCount < 12) {
    return { score: 0, label: "Low intent", detail: "Note suggests limited commercial intent", color: "#ED1C24" };
  }

  let pts = 0;
  let reasons = [];
  let color = "#94A3B8";

  // Base points for writing a meaningful note
  if (wordCount >= 4)  { pts += 1; }
  if (wordCount >= 10) { pts += 1; reasons.push("detailed note"); }
  if (wordCount >= 20) { pts += 1; reasons.push("comprehensive"); }

  // Signal bonuses — stacked
  if (hasBuying)     { pts += 3; reasons.push("buying signals"); color = C.blue; }
  if (hasAuthority)  { pts += 3; reasons.push("decision authority confirmed"); color = C.green; }
  if (hasTimeline)   { pts += 2; reasons.push("timeline mentioned"); }
  if (hasQuantity)   { pts += 1; reasons.push("scale/quantity noted"); }
  if (hasTechnical)  { pts += 1; reasons.push("technical requirements"); }
  if (hasCompetitor) { pts += 1; reasons.push("competitor context"); }

  // Cap and label
  pts = Math.min(pts, 10);
  if (pts >= 8) { color = C.green; }
  else if (pts >= 5) { color = C.blue; }
  else if (pts >= 3) { color = C.yellow; }

  const label = pts >= 8 ? "Strong buyer signal" : pts >= 6 ? "Active evaluator" : pts >= 4 ? "Commercial interest" : pts >= 2 ? "General interest" : "Minimal signal";
  const detail = reasons.length > 0 ? reasons.slice(0, 3).join(" · ") : "basic note";

  return { score: pts, label, detail, color };
}

const Tab       = ({id,label,active,onClick})=><button onClick={()=>onClick(id)} style={{padding:"9px 14px",fontSize:11,fontWeight:600,cursor:"pointer",border:"none",borderBottom:`2px solid ${active?C.navy:"transparent"}`,background:"transparent",color:active?C.navy:C.muted,marginBottom:-1,fontFamily:F}}>{label}</button>;

// ═══════════════════════════════════════════════════════════════════
// SCREEN 1 — Login + Exhibition Setup
// ═══════════════════════════════════════════════════════════════════
// ── Sample event catalogue data ───────────────────────────────────────────────
// ── Create Event Wizard ───────────────────────────────────────────────────────
function CreateEventWizard({onBack, onCreated}) {
  const [step, setStep] = useState(1);
  const TOTAL = 5;

  // Step 1 — Basic details
  const [evName,  setEvName]  = useState("");
  const [evType,  setEvType]  = useState("medtech");
  const [dateFrom,setDateFrom]= useState("");
  const [dateTo,  setDateTo]  = useState("");
  const [venue,   setVenue]   = useState("");
  const [country, setCountry] = useState("Singapore");

  // Step 2 — Company & product
  const [coName,   setCoName]  = useState("Siemens Healthineers");
  const [product,  setProduct] = useState("");
  const [website,  setWebsite] = useState("");
  const [boothSize,setBoothSize]=useState("9");

  // Step 3 — Target categories
  const [selCats, setSelCats] = useState([]);

  // Step 4 — ICP setup
  const [icpRole,   setIcpRole]  = useState([]);
  const [icpSize,   setIcpSize]  = useState([]);
  const [icpReason, setIcpReason]= useState([]);

  // Step 5 — Exhibitor intent
  const [intentWhy,    setIntentWhy]    = useState("");
  const [icpResearch,  setIcpResearch]  = useState(null);
  const [icpLoading,   setIcpLoading]   = useState(false);
  const [dynamicCats,  setDynamicCats]  = useState([]);
  const [dynamicRoles, setDynamicRoles] = useState([]);
  const [intentBuyers, setIntentBuyers] = useState("");

  const selType = EX_TYPES.find(t => t.id === evType) || EX_TYPES[0];

  const iS = {width:"100%",padding:"10px 13px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontFamily:F,boxSizing:"border-box",outline:"none",background:C.white,color:C.dark};
  const lS = {display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:5,textTransform:"uppercase",letterSpacing:.08};

  const toggle = (arr,setArr,v) => setArr(p => p.includes(v) ? p.filter(x=>x!==v) : [...p,v]);
  const chip = (active,label,onClick) => (
    <button onClick={onClick} style={{padding:"6px 13px",border:`1.5px solid ${active?C.navy:"#E2E8F0"}`,borderRadius:99,fontSize:12,fontWeight:active?600:400,cursor:"pointer",background:active?C.navy:C.white,color:active?C.white:C.muted,fontFamily:F,transition:"all .12s"}}>{label}</button>
  );

  const evNameErr  = V.eventName(evName);
  const venueErr   = V.venue(venue);
  const websiteErr = V.website(website);
  const coNameErr  = V.companyName(coName);
  const dateRangeErr = dateFrom && dateTo && new Date(dateTo) < new Date(dateFrom)
    ? "End date must be after start date"
    : null;
  const step1OK = evName && dateFrom && dateTo && venue && !evNameErr && !venueErr && !dateRangeErr;

  // Fetch real ICP data from Claude when moving from step 1 to step 3
  const fetchEventICP = async () => {
    if (!evName || icpResearch) return; // already fetched
    setIcpLoading(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const params = new URLSearchParams({ event_name: evName, venue: venue || "" });
      const res = await fetch(`/api/v1/events/research-icp?${params}`, {
        headers: { "x-fingoh-auth": `Bearer ${token}` },
      });
      if (res.ok) {
        const data = await res.json();
        setIcpResearch(data);
        if (data.visitor_categories?.length > 0) setDynamicCats(data.visitor_categories);
        if (data.visitor_roles?.length > 0)      setDynamicRoles(data.visitor_roles);
      }
    } catch(e) { console.error("ICP research failed:", e); }
    finally { setIcpLoading(false); }
  };
  const step2OK = coName && product;
  const step3OK = selCats.length > 0;
  const step4OK = true;
  const step5OK = intentWhy.trim().length > 10;

  const canNext = [null, step1OK, step2OK, step3OK, step4OK, step5OK][step];

  // Parse intent signals from free text
  const parseIntentSignals = (text) => {
    if (!text || text.trim().length < 5) return [];
    const t = text.toLowerCase();
    const signals = [];
    if (/launch|introduc|showcase|new product|debut/.test(t))    signals.push({icon:"🚀", label:"Product launch"});
    if (/lead|pipeline|prospect|sales|revenue|deal/.test(t))     signals.push({icon:"🎯", label:"Lead generation"});
    if (/partner|distribut|resell|channel|agent/.test(t))        signals.push({icon:"🤝", label:"Partnership / distribution"});
    if (/brand|awareness|visibility|market presence/.test(t))    signals.push({icon:"📢", label:"Brand awareness"});
    if (/compet|benchmark|market intel|research|trend/.test(t))  signals.push({icon:"🔍", label:"Market intelligence"});
    if (/recruit|hire|talent|team/.test(t))                      signals.push({icon:"👥", label:"Talent acquisition"});
    if (/investor|fund|capital|raise/.test(t))                   signals.push({icon:"💰", label:"Investor interest"});
    if (/expand|enter|new market|region|geography/.test(t))      signals.push({icon:"🌏", label:"Market expansion"});
    return signals;
  };

  const parseBuyerSignals = (text) => {
    if (!text || text.trim().length < 5) return [];
    const t = text.toLowerCase();
    const signals = [];
    if (/hospital|clinic|healthcare|medical|health system/.test(t))   signals.push({icon:"🏥", label:"Healthcare providers"});
    if (/procure|purchas|buy|sourcing|procurement/.test(t))           signals.push({icon:"🛒", label:"Active buyers / procurement"});
    if (/cto|cio|vp|director|head of|c-suite|executive/.test(t))     signals.push({icon:"👔", label:"Senior decision-makers"});
    if (/it|technology|digital|software|systems/.test(t))             signals.push({icon:"💻", label:"IT / technology teams"});
    if (/sme|small|mid.?size|startup/.test(t))                        signals.push({icon:"🏢", label:"SMEs / startups"});
    if (/government|public|ministry|nhs|authority/.test(t))           signals.push({icon:"🏛️", label:"Government / public sector"});
    if (/distribut|resell|dealer|channel/.test(t))                    signals.push({icon:"🔗", label:"Distributors / resellers"});
    if (/research|academia|university|lab/.test(t))                   signals.push({icon:"🔬", label:"Research / academia"});
    return signals;
  };

  const intentSignals = parseIntentSignals(intentWhy);
  const buyerSignals  = parseBuyerSignals(intentBuyers);

  const [creating, setCreating] = useState(false);
  const [createError, setCreateError] = useState(null);
  const [created, setCreated] = useState(false);
  const [createdEvent, setCreatedEvent] = useState(null);

  const handleCreate = () => {
    setCreating(true); setCreateError(null);
    apiCreateEvent({
      name: evName, type: evType, type_label: selType.label,
      date_from: dateFrom, date_to: dateTo, venue, country,
      company: coName, product, website, booth_size: boothSize,
      categories: selCats.length ? selCats : selType.cats,
      icp_roles: icpRole, icp_company_sizes: icpSize, icp_visit_reasons: icpReason,
      intent_why: intentWhy, intent_buyers: intentBuyers,
      intent_signals: intentSignals, buyer_signals: buyerSignals,
    })
    .then(newEvent => {
      setCreating(false);
      setCreated(true);
      setCreatedEvent(newEvent);
    })
    .catch(err => { setCreateError(err.message); setCreating(false); });
  };

  const handleLaunch = () => {
    if(!createdEvent) return;
    onCreated({
      name: createdEvent.name, type: createdEvent.type, id: createdEvent.id,
      cats: selCats.length ? selCats : selType.cats,
      dateFrom: createdEvent.date_from, dateTo: createdEvent.date_to,
      venue: createdEvent.venue, country: createdEvent.country,
      company: createdEvent.company, product: createdEvent.product,
      intentWhy, intentBuyers, intentSignals, buyerSignals,
      icpRole, icpSize, icpReason,
    });
  };

  const steps = ["Event details","Your company","Target categories","ICP setup","Your intent"];

  return (
    <div style={{minHeight:"100vh",background:C.light,fontFamily:F}}>
      {/* Top bar */}
      <div style={{background:C.white,borderBottom:"1px solid #E2E8F0",height:54,display:"flex",alignItems:"center",padding:"0 28px",position:"sticky",top:0,zIndex:50}}>
        <div style={{display:"flex",alignItems:"center",gap:8,marginRight:32}}>
          <img src={LOGO_BLACK} alt="Fingoh" style={{height:24,display:"block"}}/>
          <span style={{fontSize:10,padding:"2px 7px",borderRadius:99,background:C.ltblue,color:C.blue,fontWeight:600}}>Exhibitor</span>
        </div>
        <button onClick={onBack} style={{fontSize:12,color:C.muted,background:"none",border:"none",cursor:"pointer",fontFamily:F,display:"flex",alignItems:"center",gap:5}}>← Back to events</button>
        <div style={{flex:1,display:"flex",justifyContent:"center",gap:0}}>
          {steps.map((s,i)=>{
            const n=i+1; const done=step>n; const active=step===n;
            return (
              <div key={n} style={{display:"flex",alignItems:"center"}}>
                <div style={{display:"flex",alignItems:"center",gap:8,padding:"4px 14px",borderRadius:99,background:active?"rgba(13,27,62,0.07)":"transparent"}}>
                  <div style={{width:22,height:22,borderRadius:"50%",background:done?C.green:active?C.navy:"#CBD5E1",color:C.white,fontSize:11,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>{done?"✓":n}</div>
                  <span style={{fontSize:11,fontWeight:600,color:active?C.navy:done?C.green:C.muted2}}>{s}</span>
                </div>
                {i<steps.length-1 && <div style={{width:28,height:1,background:"#E2E8F0",flexShrink:0}}/>}
              </div>
            );
          })}
        </div>
        <div style={{marginLeft:32,fontSize:11,color:C.muted2}}>Step {step} of {TOTAL}</div>
      </div>

      {/* Body */}
      <div style={{maxWidth:760,margin:"0 auto",padding:"40px 24px"}}>
        <div style={{background:C.white,border:"1px solid #E2E8F0",borderRadius:16,overflow:"hidden",boxShadow:"0 2px 16px rgba(13,27,62,0.06)"}}>

          {/* Step header */}
          <div style={{padding:"22px 28px",borderBottom:"1px solid #E2E8F0",background:"linear-gradient(135deg,#F8FAFC,#FFFFFF)"}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <div style={{width:36,height:36,borderRadius:10,background:C.ltblue,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>{["🎪","🏢","🎯","🎖️","✦"][step-1]}</div>
              <div>
                <h2 style={{fontSize:17,fontWeight:700,color:C.navy,margin:0}}>{steps[step-1]}</h2>
                <p style={{fontSize:12,color:C.muted,margin:0}}>{["Tell us about the exhibition","Your company and booth details","Which visitor categories are you targeting?","Define your ideal customer profile for IEI scoring","Describe your goals and the buyers you want to meet"][step-1]}</p>
              </div>
            </div>
          </div>

          <div style={{padding:28}}>

            {/* ── STEP 1: Event details ── */}
            {step===1 && (
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:28}}>
                <div style={{display:"flex",flexDirection:"column",gap:16}}>
                  <div>
                    <label style={lS}>Exhibition name *</label>
                    <input value={evName} onChange={e=>setEvName(e.target.value)} placeholder="e.g. MedTech Asia 2025" style={{...iS, borderColor: evName && evNameErr ? "#DC2626" : "#E2E8F0"}}/>
                    {evName && evNameErr && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{evNameErr}</p>}
                  </div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                    <div><label style={lS}>Start date *</label><input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)} style={iS}/></div>
                    <div>
                      <label style={lS}>End date *</label>
                      <input type="date" value={dateTo} min={dateFrom || undefined} onChange={e=>setDateTo(e.target.value)} style={{...iS, borderColor: dateRangeErr ? "#DC2626" : "#E2E8F0"}}/>
                      {dateRangeErr && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{dateRangeErr}</p>}
                    </div>
                  </div>
                  <div>
                    <label style={lS}>Venue *</label>
                    <input value={venue} onChange={e=>setVenue(e.target.value)} placeholder="e.g. Marina Bay Sands Expo, Singapore" style={{...iS, borderColor: venue && venueErr ? "#DC2626" : "#E2E8F0"}}/>
                    {venue && venueErr && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{venueErr}</p>}
                  </div>
                  <div>
                    <label style={lS}>Country</label>
                    <select value={country} onChange={e=>setCountry(e.target.value)} style={{...iS,height:40}}>
                      {["Singapore","Malaysia","Indonesia","Thailand","Philippines","Vietnam","India","UAE","UK","Australia"].map(c=><option key={c}>{c}</option>)}
                    </select>
                  </div>
                </div>
                <div>
                  <label style={lS}>Exhibition type *</label>
                  <div style={{maxHeight:360,overflowY:"auto",display:"flex",flexDirection:"column",gap:8,paddingRight:4}}>
                    {ET_SECTORS.map(sector=>(
                      <div key={sector}>
                        <p style={{fontSize:9,fontWeight:700,color:C.muted2,textTransform:"uppercase",letterSpacing:.12,marginBottom:4}}>{sector}</p>
                        <div style={{display:"flex",flexDirection:"column",gap:3}}>
                          {EX_TYPES.filter(t=>t.sector===sector).map(t=>(
                            <div key={t.id} onClick={()=>{setEvType(t.id);setSelCats([]);}}
                              style={{padding:"7px 11px",border:`1.5px solid ${evType===t.id?C.blue:"#E2E8F0"}`,borderRadius:8,cursor:"pointer",background:evType===t.id?C.ltblue:C.white,display:"flex",alignItems:"center",gap:8,transition:"all .12s"}}>
                              <span style={{fontSize:13}}>{t.icon}</span>
                              <span style={{fontSize:12,fontWeight:evType===t.id?700:400,color:evType===t.id?C.navy:C.muted,lineHeight:1.3}}>{t.label}</span>
                              {evType===t.id && <span style={{marginLeft:"auto",fontSize:10,color:C.blue,fontWeight:700}}>✓</span>}
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* ── STEP 2: Company & booth ── */}
            {step===2 && (
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:28}}>
                <div style={{display:"flex",flexDirection:"column",gap:16}}>
                  <div>
                    <label style={lS}>Company name *</label>
                    <input value={coName} onChange={e=>setCoName(e.target.value)} style={{...iS, borderColor: coName && coNameErr ? "#DC2626" : "#E2E8F0"}}/>
                    {coName && coNameErr && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{coNameErr}</p>}
                  </div>
                  <div><label style={lS}>Product / solution *</label><input value={product} onChange={e=>setProduct(e.target.value)} placeholder="e.g. Diagnostic imaging & AI-powered radiology" style={iS}/></div>
                  <div>
                    <label style={lS}>Company website</label>
                    <input value={website} onChange={e=>setWebsite(e.target.value)} placeholder="https://www.company.com" style={{...iS, borderColor: website && websiteErr ? "#DC2626" : "#E2E8F0"}}/>
                    {website && websiteErr && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{websiteErr}</p>}
                  </div>
                  <div>
                    <label style={lS}>Booth size (sqm)</label>
                    <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                      {["9","18","27","36","54","72","Custom"].map(s=>(
                        <button key={s} onClick={()=>setBoothSize(s)}
                          style={{padding:"7px 16px",border:`1.5px solid ${boothSize===s?C.navy:"#E2E8F0"}`,borderRadius:8,fontSize:12,fontWeight:boothSize===s?700:400,cursor:"pointer",background:boothSize===s?C.navy:C.white,color:boothSize===s?C.white:C.muted,fontFamily:F}}>
                          {s}{s!=="Custom"?" m²":""}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
                <div>
                  <p style={{fontSize:12,fontWeight:600,color:C.navy,marginBottom:12}}>Exhibition type selected</p>
                  <div style={{background:C.ltblue,border:`1px solid ${C.blue}30`,borderRadius:12,padding:18,marginBottom:16}}>
                    <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
                      <span style={{fontSize:24}}>{selType.icon}</span>
                      <div>
                        <p style={{fontSize:14,fontWeight:700,color:C.navy,margin:0}}>{selType.label}</p>
                        <p style={{fontSize:11,color:C.muted,margin:0}}>{selType.sector}</p>
                      </div>
                    </div>
                    <p style={{fontSize:10,color:C.muted,marginBottom:6}}>Fingoh will auto-configure IEI scoring for these categories:</p>
                    <div style={{display:"flex",flexWrap:"wrap",gap:4}}>
                      {selType.cats.map((c,i)=><span key={i} style={{fontSize:10,padding:"2px 8px",borderRadius:99,background:"rgba(41,171,226,0.12)",color:C.blue}}>{c}</span>)}
                    </div>
                  </div>
                  <div style={{background:C.ltgrn,border:"1px solid #86EFAC",borderRadius:10,padding:14}}>
                    <p style={{fontSize:11,fontWeight:600,color:"#14532D",margin:0,marginBottom:4}}>✓ What Fingoh auto-configures</p>
                    <p style={{fontSize:11,color:"#166534",margin:0,lineHeight:1.6}}>ICP scoring model · IEI tiers · Category filters · Intent dimensions · Visitor signals</p>
                  </div>
                </div>
              </div>
            )}

            {/* ── STEP 3: Target categories ── */}
            {step===3 && (
              <div>
                <p style={{fontSize:13,color:C.muted,marginBottom:18}}>Select the visitor categories most relevant to your products. Fingoh will weight IEI scores higher for visitors with matching interests.</p>

                {/* ICP research status */}
                {icpLoading && (
                  <div style={{display:"flex",alignItems:"center",gap:10,padding:"12px 16px",background:"#EFF6FF",border:"1px solid #BFDBFE",borderRadius:10,marginBottom:16}}>
                    <div style={{width:16,height:16,border:"2px solid #3B82F6",borderTopColor:"transparent",borderRadius:"50%",animation:"spin 1s linear infinite",flexShrink:0}}/>
                    <p style={{fontSize:12,color:"#1D4ED8",margin:0,fontWeight:500}}>✦ Researching {evName} visitor profiles…</p>
                  </div>
                )}
                {icpResearch && !icpLoading && (
                  <div style={{padding:"10px 14px",background:"#F0FDF4",border:"1px solid #86EFAC",borderRadius:10,marginBottom:16}}>
                    <p style={{fontSize:11,color:"#14532D",margin:0}}>✓ Found real visitor data for <strong>{evName}</strong> · {icpResearch.event_description}</p>
                  </div>
                )}

                <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
                  {(dynamicCats.length > 0 ? dynamicCats : selType.cats).map(cat=>{
                    const on = selCats.includes(cat);
                    return (
                      <div key={cat} onClick={()=>toggle(selCats,setSelCats,cat)}
                        style={{padding:"12px 14px",border:`1.5px solid ${on?C.navy:"#E2E8F0"}`,borderRadius:10,cursor:"pointer",background:on?C.navy:C.white,transition:"all .12s"}}>
                        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                          <span style={{fontSize:12,fontWeight:on?700:400,color:on?C.white:C.dark,lineHeight:1.4}}>{cat}</span>
                          {on && <span style={{fontSize:14,color:C.green}}>✓</span>}
                        </div>
                      </div>
                    );
                  })}
                </div>
                {selCats.length===0 && (
                  <div style={{marginTop:16,padding:12,background:C.ltylw,border:"1px solid #FCD34D",borderRadius:8}}>
                    <p style={{fontSize:11,color:C.amber,margin:0}}>⚠ Select at least one category to continue. Fingoh uses these to tune the IEI scoring model.</p>
                  </div>
                )}
                {selCats.length>0 && (
                  <div style={{marginTop:16,padding:12,background:C.ltgrn,border:"1px solid #86EFAC",borderRadius:8}}>
                    <p style={{fontSize:11,color:"#14532D",margin:0}}><strong>{selCats.length}</strong> categor{selCats.length===1?"y":"ies"} selected · Fingoh will prioritise visitors with these interests in IEI scoring</p>
                  </div>
                )}
              </div>
            )}

            {/* ── STEP 4: ICP setup ── */}
            {step===4 && (
              <div style={{display:"flex",flexDirection:"column",gap:22}}>
                <div>
                  <p style={{fontSize:12,fontWeight:600,color:C.navy,marginBottom:10}}>Target visitor roles <span style={{fontSize:11,fontWeight:400,color:C.muted}}>(select all that apply)</span></p>
                  <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                    {(dynamicRoles.length > 0 ? dynamicRoles : ["C-Suite / CEO / MD","VP / Director","Procurement Manager","Clinical / Technical Lead","IT Manager","Department Head","Business Owner","Consultant / Advisor"]).map(r=>
                      chip(icpRole.includes(r),r,()=>toggle(icpRole,setIcpRole,r))
                    )}
                  </div>
                </div>
                {icpResearch?.industries?.length > 0 && (
                  <div>
                    <p style={{fontSize:12,fontWeight:600,color:C.navy,marginBottom:10}}>Target industries <span style={{fontSize:10,fontWeight:400,color:C.muted}}>(from {evName} research)</span></p>
                    <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                      {icpResearch.industries.map(ind =>
                        chip(icpReason.includes(ind), ind, ()=>toggle(icpReason, setIcpReason, ind))
                      )}
                    </div>
                  </div>
                )}

                <div>
                  <p style={{fontSize:12,fontWeight:600,color:C.navy,marginBottom:10}}>Target company sizes</p>
                  <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                    {["1–50 employees","51–200 employees","201–500 employees","501–1000 employees","1000+ employees","Government / Public sector","Academic / Research"].map(s=>
                      chip(icpSize.includes(s),s,()=>toggle(icpSize,setIcpSize,s))
                    )}
                  </div>
                </div>
                <div>
                  <p style={{fontSize:12,fontWeight:600,color:C.navy,marginBottom:10}}>Primary visit reasons you want to attract</p>
                  <div style={{display:"flex",flexWrap:"wrap",gap:8}}>
                    {["Active sourcing / procurement","Product evaluation","Comparing vendors","Technology scouting","Market research","Partnership / distribution","Academic / research","General interest"].map(r=>
                      chip(icpReason.includes(r),r,()=>toggle(icpReason,setIcpReason,r))
                    )}
                  </div>
                </div>
                <div style={{background:C.ltnavy,border:"1px solid #C7D0E8",borderRadius:12,padding:16}}>
                  <p style={{fontSize:11,fontWeight:700,color:C.navy,margin:0,marginBottom:4}}>◎ IEI scoring will be tuned to your ICP</p>
                  <p style={{fontSize:11,color:C.muted,margin:0,lineHeight:1.6}}>
                    {icpRole.length>0 || icpReason.length>0
                      ? `Targeting ${icpRole.length>0?icpRole.slice(0,2).join(", "):"all roles"}${icpReason.length>0?" · Visitors with "+icpReason.slice(0,2).join(", ")+" will score higher":""}`
                      : "No ICP filters set — Fingoh will score all visitors equally. You can refine this at any time."}
                  </p>
                </div>
              </div>
            )}

            {/* ── STEP 5: Exhibitor intent ── */}
            {step===5 && (
              <div style={{display:"flex",flexDirection:"column",gap:20}}>
                <div style={{background:`linear-gradient(135deg,${C.ltnavy},#EEF2FF)`,border:"1px solid #C7D0E8",borderRadius:12,padding:"14px 18px",display:"flex",gap:12,alignItems:"flex-start"}}>
                  <span style={{fontSize:20,flexShrink:0}}>✦</span>
                  <div>
                    <p style={{fontSize:12,fontWeight:700,color:C.navy,margin:0,marginBottom:3}}>Fingoh reads your intent</p>
                    <p style={{fontSize:11,color:C.muted,margin:0,lineHeight:1.6}}>Write naturally — Fingoh parses your text to extract intent signals and buyer profiles, then uses them to tune IEI scoring so the most relevant visitors rank higher for you.</p>
                  </div>
                </div>

                {/* Why attending */}
                <div>
                  <label style={lS}>Why are you attending this exhibition? *</label>
                  <p style={{fontSize:11,color:C.muted2,marginBottom:8,marginTop:0}}>Tell us about your goals — what you want to achieve, products you're launching, deals you're looking to close, or markets you want to enter.</p>
                  <textarea value={intentWhy} onChange={e=>setIntentWhy(e.target.value)}
                    rows={4} placeholder={"e.g. We are launching our new AI-powered CT scanner at this show and want to generate qualified leads from hospital procurement teams across Southeast Asia. We're also looking to appoint regional distributors in Indonesia and Malaysia, and showcase our updated PACS integration to existing customers considering upgrade."}
                    style={{...iS,resize:"vertical",lineHeight:1.65,fontFamily:F}}/>
                  {/* Live signal parse */}
                  {intentSignals.length > 0 && (
                    <div style={{marginTop:10,padding:"10px 14px",background:C.ltgrn,border:"1px solid #86EFAC",borderRadius:8}}>
                      <p style={{fontSize:10,fontWeight:700,color:"#14532D",margin:0,marginBottom:6,textTransform:"uppercase",letterSpacing:.06}}>✦ Intent signals detected</p>
                      <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                        {intentSignals.map((s,i)=>(
                          <span key={i} style={{fontSize:11,padding:"3px 10px",borderRadius:99,background:"rgba(57,181,74,0.15)",color:"#14532D",fontWeight:600}}>{s.icon} {s.label}</span>
                        ))}
                      </div>
                    </div>
                  )}
                  {intentWhy.length > 0 && intentWhy.trim().length <= 10 && (
                    <p style={{fontSize:11,color:C.amber,marginTop:6}}>⚠ Please describe your intent in a little more detail (at least a sentence).</p>
                  )}
                </div>

                {/* Who they want to meet */}
                <div>
                  <label style={lS}>What type of visitors or buyers do you want to meet?</label>
                  <p style={{fontSize:11,color:C.muted2,marginBottom:8,marginTop:0}}>Describe the roles, organisations, or profiles of people you most want to connect with — the more specific, the better Fingoh can score and surface them.</p>
                  <textarea value={intentBuyers} onChange={e=>setIntentBuyers(e.target.value)}
                    rows={4} placeholder={"e.g. We want to meet heads of procurement and clinical directors at private hospitals and large hospital networks across ASEAN. We're particularly interested in hospitals with 200+ beds that are due for equipment refresh in the next 12 months. Decision-makers with budget authority, not just evaluators."}
                    style={{...iS,resize:"vertical",lineHeight:1.65,fontFamily:F}}/>
                  {/* Live buyer signal parse */}
                  {buyerSignals.length > 0 && (
                    <div style={{marginTop:10,padding:"10px 14px",background:C.ltblue,border:`1px solid ${C.blue}40`,borderRadius:8}}>
                      <p style={{fontSize:10,fontWeight:700,color:C.blue,margin:0,marginBottom:6,textTransform:"uppercase",letterSpacing:.06}}>✦ Buyer profile signals detected</p>
                      <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                        {buyerSignals.map((s,i)=>(
                          <span key={i} style={{fontSize:11,padding:"3px 10px",borderRadius:99,background:"rgba(41,171,226,0.12)",color:C.navy,fontWeight:600}}>{s.icon} {s.label}</span>
                        ))}
                      </div>
                    </div>
                  )}
                </div>

                {/* How it feeds IEI */}
                <div style={{background:C.light,border:"1px solid #E2E8F0",borderRadius:10,padding:"12px 16px"}}>
                  <p style={{fontSize:11,fontWeight:600,color:C.navy,margin:0,marginBottom:6}}>How Fingoh uses your intent</p>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                    {[
                      ["◎ IEI scoring","Visitors matching your buyer profile get higher intent scores"],
                      ["🎯 ICP matching","Your target roles and org types sharpen the Perfect / Good / Weak ICP tiers"],
                      ["⚡ Live alerts","Staff app alerts prioritise visitors whose signals match your intent"],
                      ["✦ Agent prompts","The Fingoh Agent uses your goals to draft personalised outreach and follow-ups"],
                    ].map(([t,d])=>(
                      <div key={t} style={{display:"flex",gap:8,alignItems:"flex-start"}}>
                        <span style={{fontSize:12,flexShrink:0,marginTop:1}}></span>
                        <div>
                          <p style={{fontSize:11,fontWeight:600,color:C.navy,margin:0}}>{t}</p>
                          <p style={{fontSize:10,color:C.muted,margin:0,marginTop:2,lineHeight:1.5}}>{d}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

          </div>

          {/* Footer nav */}
          <div style={{padding:"16px 28px",borderTop:"1px solid #E2E8F0",background:"#FAFAFA",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <button onClick={step===1?onBack:()=>setStep(s=>s-1)}
              style={{padding:"9px 20px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontWeight:600,cursor:"pointer",background:C.white,color:C.muted,fontFamily:F}}>
              {step===1?"← Cancel":"← Back"}
            </button>
            <div style={{display:"flex",alignItems:"center",gap:8}}>
              {[1,2,3,4,5].map(n=>(
                <div key={n} style={{width:n===step?22:7,height:7,borderRadius:99,background:n===step?C.navy:n<step?C.green:"#CBD5E1",transition:"all .2s"}}/>
              ))}
            </div>
            {step < TOTAL ? (
              <button onClick={()=>{if(canNext){if(step===1)fetchEventICP();setStep(s=>s+1);}}} disabled={!canNext}
                style={{padding:"9px 22px",background:canNext?C.blue:"#CBD5E1",color:C.white,border:"none",borderRadius:8,fontSize:13,fontWeight:700,cursor:canNext?"pointer":"not-allowed",fontFamily:F}}>
                Next →
              </button>
            ) : (
              <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:6}}>
                {createError && <p style={{fontSize:11,color:C.red,margin:0}}>{createError}</p>}
                {!created ? (
                  <button onClick={handleCreate} disabled={creating}
                    style={{padding:"9px 22px",background:creating?"#CBD5E1":C.green,color:C.white,border:"none",borderRadius:8,fontSize:13,fontWeight:700,cursor:creating?"not-allowed":"pointer",fontFamily:F}}>
                    {creating ? "Creating event..." : "Create & Launch ↗"}
                  </button>
                ) : (
                  <div style={{display:"flex",alignItems:"center",gap:10}}>
                    <span style={{fontSize:12,color:C.green,fontWeight:600}}>✓ Event created successfully!</span>
                    <button onClick={onBack}
                      style={{padding:"9px 16px",background:C.white,color:C.navy,border:"1px solid #E2E8F0",borderRadius:8,fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:F}}>
                      ← Back to events
                    </button>
                    <button onClick={handleLaunch}
                      style={{padding:"9px 22px",background:C.navy,color:C.white,border:"none",borderRadius:8,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:F}}>
                      Open Fingoh ↗
                    </button>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Post-login Event Home ─────────────────────────────────────────────────────
function EventHome({onLaunch, onCreateEvent, profile}) {
  const [showTeam, setShowTeam] = useState(false);

  // Real API state
  const [myEvents, setMyEvents]         = useState([]);
  const [eventsLoading, setEventsLoading] = useState(true);
  const [staffList, setStaffList]       = useState([]);
  const [staffLoading, setStaffLoading] = useState(true);
  const [staffForm, setStaffForm]       = useState({name:"",email:"",title:"",responsibility:""});
  const [staffSaved, setStaffSaved]     = useState(false);
  const [staffError, setStaffError]     = useState(null);

  const sfUpd = (k,v) => setStaffForm(p=>({...p,[k]:v}));
  const sfReady = staffForm.name && staffForm.email && staffForm.title;

  const refreshEvents = () => {
    setEventsLoading(true);
    getEvents()
      .then(data => { setMyEvents(data || []); setEventsLoading(false); })
      .catch(() => setEventsLoading(false));
  };

  useEffect(() => {
    getEvents()
      .then(data => { setMyEvents(data || []); setEventsLoading(false); })
      .catch(() => setEventsLoading(false));
    getStaff()
      .then(data => { setStaffList(data || []); setStaffLoading(false); })
      .catch(() => setStaffLoading(false));
  }, []);

  const [staffErrors, setStaffErrors] = useState({});

  const addStaff = () => {
    const errors = validateForm(staffForm, SCHEMAS.staff);
    setStaffErrors(errors);
    if (Object.keys(errors).length > 0) return;
    setStaffError(null);
    apiAddStaff(staffForm)
      .then(s => {
        setStaffList(p=>[...p,s]);
        setStaffForm({name:"",email:"",title:"",responsibility:""});
        setStaffSaved(true); setTimeout(()=>setStaffSaved(false),2000);
      })
      .catch(err => setStaffError(err.message));
  };

  const removeStaff = id => {
    apiRemoveStaff(id).then(() => setStaffList(p=>p.filter(s=>s.id!==id)));
  };

  const iS = {width:"100%",padding:"9px 12px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontFamily:F,boxSizing:"border-box",outline:"none",background:C.white};
  const lS = {display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:5,textTransform:"uppercase",letterSpacing:.08};

  const statusStyle = {
    open:    {bg:C.ltgrn,   tc:"#14532D", label:"Open"},
    closing: {bg:C.ltylw,   tc:C.amber,   label:"Closing soon"},
    closed:  {bg:"#F1F5F9", tc:C.muted,   label:"Closed"},
  };

  return (
    <div style={{minHeight:"100vh",background:C.light,fontFamily:F}}>
      {/* Nav */}
      <div style={{background:C.white,borderBottom:"1px solid #E2E8F0",height:54,display:"flex",alignItems:"center",padding:"0 28px",position:"sticky",top:0,zIndex:50}}>
        <div style={{display:"flex",alignItems:"center",gap:8,flex:1}}>
          <img src={LOGO_BLACK} alt="Fingoh" style={{height:24,display:"block"}}/>
          <span style={{fontSize:10,padding:"2px 7px",borderRadius:99,background:C.ltblue,color:C.blue,fontWeight:600}}>Exhibitor</span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          {/* My Team button */}
          <button onClick={()=>setShowTeam(s=>!s)}
            style={{display:"flex",alignItems:"center",gap:7,padding:"6px 14px",border:`1.5px solid ${showTeam?C.navy:"#E2E8F0"}`,borderRadius:8,cursor:"pointer",background:showTeam?C.navy:C.white,color:showTeam?C.white:C.muted,fontSize:12,fontWeight:600,fontFamily:F,transition:"all .12s"}}>
            <span style={{fontSize:15}}>👥</span> My Team
            <span style={{fontSize:10,padding:"1px 6px",borderRadius:99,background:showTeam?"rgba(255,255,255,0.2)":C.ltnavy,color:showTeam?C.white:C.navy,fontWeight:700}}>{staffList.length}</span>
          </button>
          <div style={{width:1,height:22,background:"#E2E8F0"}}/>
          <span style={{fontSize:12,color:C.muted}}>{profile?.org_name || "My Organisation"}</span>
          <UserMenu profile={profile}/>
        </div>
      </div>

      {/* My Team panel — slides down from nav */}
      {showTeam && (
        <div style={{background:C.white,borderBottom:"1px solid #E2E8F0",padding:"24px 28px",boxShadow:"0 4px 16px rgba(13,27,62,0.07)"}}>
          <div style={{maxWidth:1100,margin:"0 auto"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
              <div>
                <h2 style={{fontSize:17,fontWeight:800,color:C.navy,margin:0,marginBottom:4}}>My Team</h2>
                <p style={{fontSize:12,color:C.muted,margin:0}}>Your booth team roster — shared across all events. Staff log in to the Staff App with their email address.</p>
              </div>
              <button onClick={()=>setShowTeam(false)}
                style={{fontSize:12,color:C.muted,background:"none",border:"1px solid #E2E8F0",borderRadius:7,cursor:"pointer",fontFamily:F,padding:"5px 12px"}}>
                ✕ Close
              </button>
            </div>

            <div style={{display:"grid",gridTemplateColumns:"340px 1fr",gap:24}}>
              {/* Add form */}
              <div style={{background:C.light,border:"1px solid #E2E8F0",borderRadius:12,padding:18,height:"fit-content"}}>
                <p style={{fontSize:11,fontWeight:700,color:C.navy,textTransform:"uppercase",letterSpacing:.06,margin:0,marginBottom:14}}>Add team member</p>
                <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:12}}>
                  <div>
                    <label style={lS}>Full name *</label>
                    <input value={staffForm.name} onChange={e=>{sfUpd("name",e.target.value); setStaffErrors(p=>({...p,name:V.name(e.target.value)}));}} placeholder="e.g. Raj Kumar" style={{...iS, borderColor: staffErrors.name ? "#DC2626" : "#E2E8F0"}}/>
                    {staffErrors.name && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{staffErrors.name}</p>}
                  </div>
                  <div>
                    <label style={lS}>Work email *</label>
                    <input value={staffForm.email} onChange={e=>{sfUpd("email",e.target.value); setStaffErrors(p=>({...p,email:V.email(e.target.value)}));}} placeholder="raj.kumar@company.com" style={{...iS, borderColor: staffErrors.email ? "#DC2626" : "#E2E8F0"}}/>
                    {staffErrors.email && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{staffErrors.email}</p>}
                  </div>
                  <div>
                    <label style={lS}>Job title *</label>
                    <input value={staffForm.title} onChange={e=>{sfUpd("title",e.target.value); setStaffErrors(p=>({...p,title:V.jobTitle(e.target.value)}));}} placeholder="e.g. Senior Sales Manager" style={{...iS, borderColor: staffErrors.title ? "#DC2626" : "#E2E8F0"}}/>
                    {staffErrors.title && <p style={{color:"#DC2626",fontSize:11,margin:"3px 0 0"}}>{staffErrors.title}</p>}
                  </div>
                  <div><label style={lS}>Responsible for</label><input value={staffForm.responsibility} onChange={e=>sfUpd("responsibility",e.target.value)} placeholder="e.g. CT & MRI — large accounts" style={iS}/></div>
                </div>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <button onClick={addStaff} disabled={!sfReady}
                    style={{flex:1,padding:"9px 0",background:sfReady?C.navy:"#CBD5E1",color:C.white,border:"none",borderRadius:8,fontSize:13,fontWeight:700,cursor:sfReady?"pointer":"not-allowed",fontFamily:F}}>
                    + Add member
                  </button>
                  {staffSaved && <span style={{fontSize:12,color:C.green,fontWeight:600}}>✓ Added!</span>}
                </div>
              </div>

              {/* Roster */}
              <div>
                <p style={{fontSize:11,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.06,marginBottom:10}}>{staffList.length} members · active across all events</p>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                  {staffList.map(s=>(
                    <div key={s.id} style={{background:C.white,border:"1px solid #E2E8F0",borderRadius:10,padding:"12px 14px",display:"flex",alignItems:"center",gap:12}}>
                      <div style={{width:40,height:40,borderRadius:"50%",background:C.navy,color:C.white,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:700,flexShrink:0}}>
                        {(s.name||"?").split(" ").map(n=>n[0]).join("").slice(0,2)}
                      </div>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2,flexWrap:"wrap"}}>
                          <span style={{fontSize:13,fontWeight:700,color:C.navy}}>{s.name}</span>
                          <span style={{fontSize:9,padding:"1px 6px",borderRadius:99,background:C.ltblue,color:C.blue,fontWeight:700}}>{s.title}</span>
                        </div>
                        <div style={{fontSize:11,color:C.muted,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{s.email}</div>
                        {s.responsibility && <div style={{fontSize:10,color:C.muted2,marginTop:2}}>📋 {s.responsibility}</div>}
                      </div>
                      <button onClick={()=>removeStaff(s.id)}
                        style={{fontSize:11,color:C.muted2,background:"none",border:"none",cursor:"pointer",fontFamily:F,padding:"4px",flexShrink:0,borderRadius:4}}
                        onMouseOver={e=>{e.currentTarget.style.color=C.red;}} onMouseOut={e=>{e.currentTarget.style.color=C.muted2;}}>
                        ✕
                      </button>
                    </div>
                  ))}
                </div>
                <div style={{marginTop:12,padding:"10px 14px",background:C.ltnavy,border:"1px solid #C7D0E8",borderRadius:8}}>
                  <p style={{fontSize:11,color:C.muted,margin:0}}>Staff log into the <strong style={{color:C.navy}}>Staff App</strong> using their email address. Their conversations and scores are attributed to them by name in the Live Dashboard — across every event they work.</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <div style={{maxWidth:1100,margin:"0 auto",padding:"36px 24px"}}>
        {/* Welcome header */}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:32}}>
          <div>
            <h1 style={{fontSize:26,fontWeight:800,color:C.navy,letterSpacing:"-0.02em",margin:0,marginBottom:4}}>Your Events</h1>
            <p style={{fontSize:13,color:C.muted,margin:0}}>Join an upcoming exhibition or create a new event to start capturing buyer intent</p>
          </div>
          <button onClick={onCreateEvent}
            style={{padding:"11px 22px",background:C.navy,color:C.white,border:"none",borderRadius:10,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:F,display:"flex",alignItems:"center",gap:8,boxShadow:"0 2px 12px rgba(13,27,62,0.18)"}}>
            <span style={{fontSize:16}}>＋</span> Create new event
          </button>
        </div>

        {/* My events — split into Upcoming and Past */}
        {(()=>{
          const today = new Date().toISOString().slice(0,10);
          const activeEvents = myEvents.filter(ev => ev.status !== "archived");
          const upcoming = activeEvents.filter(ev => !ev.date_to || ev.date_to >= today);
          const past     = activeEvents.filter(ev => ev.date_to && ev.date_to < today);

          const EventCard = ({ev}) => (
            <div key={ev.id} style={{background:C.white,border:`2px solid ${C.navy}`,borderRadius:14,padding:18,cursor:"pointer",transition:"all .15s",position:"relative"}}
              onMouseOver={e=>{e.currentTarget.style.boxShadow="0 6px 24px rgba(13,27,62,0.12)";}}
              onMouseOut={e=>{e.currentTarget.style.boxShadow="none";}}>
              <div style={{position:"absolute",top:14,right:14,fontSize:9,padding:"3px 9px",borderRadius:99,background:"#DBEAFE",color:C.blue,fontWeight:700}}>REGISTERED</div>
              <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
                <div style={{width:38,height:38,borderRadius:10,background:C.ltnavy,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>{EX_TYPES.find(t=>t.id===ev.type)?.icon||"🎪"}</div>
                <div>
                  <p style={{fontSize:13,fontWeight:700,color:C.navy,margin:0,lineHeight:1.3}}>{ev.name}</p>
                  <p style={{fontSize:11,color:C.muted,margin:0}}>{ev.date_from} – {ev.date_to}</p>
                </div>
              </div>
              <p style={{fontSize:11,color:C.muted,margin:0,marginBottom:14}}>📍 {ev.venue}</p>
              <button onClick={async (e)=>{
                const btn = e.currentTarget;
                btn.disabled = true;
                btn.innerHTML = '<span style="display:inline-flex;align-items:center;gap:6px;justify-content:center"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" style="animation:spin 0.8s linear infinite;flex-shrink:0"><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg> Opening…</span>';
                try {
                  const full = await getEvent(ev.id);
                  onLaunch({
                    name: full.name, type: full.type, id: full.id,
                    cats: (full.categories && full.categories.length) ? full.categories : (EX_TYPES.find(t=>t.id===full.type)?.cats||[]),
                    dateFrom: full.date_from, dateTo: full.date_to,
                    venue: full.venue, country: full.country,
                    company: full.company, product: full.product, website: full.website, boothSize: full.booth_size,
                    icpRole: full.icp?.roles || [], icpSize: full.icp?.company_sizes || [], icpReason: full.icp?.visit_reasons || [],
                    intentWhy: full.intent?.intent_why || "", intentBuyers: full.intent?.intent_buyers || "",
                    intentSignals: full.intent?.intent_signals || [], buyerSignals: full.intent?.buyer_signals || [],
                  });
                } catch (e) {
                  // Fallback to minimal data if fetch fails
                  onLaunch({name:ev.name,type:ev.type,id:ev.id,cats:EX_TYPES.find(t=>t.id===ev.type)?.cats||[],dateFrom:ev.date_from,dateTo:ev.date_to,venue:ev.venue,company:ev.company,product:ev.product});
                }
              }}
                style={{width:"100%",padding:"9px 0",background:C.navy,color:C.white,border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
                Open Fingoh ↗
              </button>
            </div>
          );

          const PastEventCard = ({ev}) => (
            <div key={ev.id} style={{background:C.white,border:`1px solid #E2E8F0`,borderRadius:14,padding:18,cursor:"pointer",transition:"all .15s",position:"relative",opacity:0.85}}
              onMouseOver={e=>{e.currentTarget.style.boxShadow="0 6px 24px rgba(13,27,62,0.08)";e.currentTarget.style.opacity=1;}}
              onMouseOut={e=>{e.currentTarget.style.boxShadow="none";e.currentTarget.style.opacity=0.85;}}>
              <div style={{position:"absolute",top:14,right:14,fontSize:9,padding:"3px 9px",borderRadius:99,background:"#F1F5F9",color:C.muted,fontWeight:700}}>COMPLETED</div>
              <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
                <div style={{width:38,height:38,borderRadius:10,background:"#F1F5F9",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>{EX_TYPES.find(t=>t.id===ev.type)?.icon||"🎪"}</div>
                <div>
                  <p style={{fontSize:13,fontWeight:700,color:C.dark,margin:0,lineHeight:1.3}}>{ev.name}</p>
                  <p style={{fontSize:11,color:C.muted,margin:0}}>{ev.date_from} – {ev.date_to}</p>
                </div>
              </div>
              <p style={{fontSize:11,color:C.muted,margin:0,marginBottom:14}}>📍 {ev.venue}</p>
              <button onClick={async ()=>{
                try {
                  const full = await getEvent(ev.id);
                  onLaunch({
                    name: full.name, type: full.type, id: full.id,
                    cats: (full.categories && full.categories.length) ? full.categories : (EX_TYPES.find(t=>t.id===full.type)?.cats||[]),
                    dateFrom: full.date_from, dateTo: full.date_to,
                    venue: full.venue, country: full.country,
                    company: full.company, product: full.product, website: full.website, boothSize: full.booth_size,
                    icpRole: full.icp?.roles || [], icpSize: full.icp?.company_sizes || [], icpReason: full.icp?.visit_reasons || [],
                    intentWhy: full.intent?.intent_why || "", intentBuyers: full.intent?.intent_buyers || "",
                    intentSignals: full.intent?.intent_signals || [], buyerSignals: full.intent?.buyer_signals || [],
                    isPast: true,
                  });
                } catch (e) {
                  // Fallback to minimal data if fetch fails
                  onLaunch({name:ev.name,type:ev.type,id:ev.id,cats:EX_TYPES.find(t=>t.id===ev.type)?.cats||[],dateFrom:ev.date_from,dateTo:ev.date_to,venue:ev.venue,company:ev.company,product:ev.product,isPast:true});
                }
              }}
                style={{width:"100%",padding:"9px 0",background:C.white,color:C.navy,border:"1px solid #E2E8F0",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
                View results ↗
              </button>
            </div>
          );

          return (<>
            {/* Upcoming events */}
            <div style={{marginBottom:32}}>
              <p style={{fontSize:11,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.1,marginBottom:12}}>Upcoming events</p>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:14}}>
                {eventsLoading ? (
                  <div style={{gridColumn:"1/-1",padding:40,textAlign:"center",color:C.muted,fontSize:13}}>Loading your events…</div>
                ) : upcoming.length===0 ? (
                  <div style={{gridColumn:"1/-1",padding:40,textAlign:"center",color:C.muted}}>
                    <div style={{fontSize:32,marginBottom:10}}>🎪</div>
                    <p style={{fontSize:14,fontWeight:600,margin:0,marginBottom:4}}>No upcoming events</p>
                    <p style={{fontSize:12,color:C.muted2,margin:0}}>Create your first event to start capturing buyer intent</p>
                  </div>
                ) : null}
                {upcoming.map(ev => <EventCard key={ev.id} ev={ev}/>)}
                {/* Create new tile */}
                <div onClick={onCreateEvent}
                  style={{border:"2px dashed #CBD5E1",borderRadius:14,padding:18,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:10,minHeight:160,transition:"all .15s"}}
                  onMouseOver={e=>{e.currentTarget.style.borderColor=C.blue;e.currentTarget.style.background="#F8FBFF";}}
                  onMouseOut={e=>{e.currentTarget.style.borderColor="#CBD5E1";e.currentTarget.style.background="transparent";}}>
                  <div style={{width:40,height:40,borderRadius:"50%",background:C.ltblue,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>＋</div>
                  <p style={{fontSize:12,fontWeight:600,color:C.muted,margin:0,textAlign:"center"}}>Create a new event</p>
                </div>
              </div>
            </div>

            {/* Past events */}
            {!eventsLoading && past.length > 0 && (
              <div style={{marginBottom:32}}>
                <p style={{fontSize:11,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.1,marginBottom:12}}>Past events</p>
                <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:14}}>
                  {past.map(ev => <PastEventCard key={ev.id} ev={ev}/>)}
                </div>
              </div>
            )}
          </>);
        })()}
      </div>
    </div>
  );
}

// ── Login Screen (auth only) ──────────────────────────────────────────────────
function LoginScreen({onLogin}) {
  const [email,setEmail]       = useState("test@fingoh.com");
  const [password,setPassword] = useState("");
  const [loading,setLoading]   = useState(false);
  const [error,setError]       = useState(null);

  const iD = {width:"100%",background:C.light,border:"1px solid #E2E8F0",borderRadius:8,padding:"10px 13px",color:C.dark,fontSize:13,fontFamily:F,outline:"none",boxSizing:"border-box"};
  const lD = {display:"block",fontSize:10,fontWeight:600,color:C.muted,marginBottom:5,textTransform:"uppercase",letterSpacing:.08};

  const handleSignIn = async () => {
    if(!email || !password){ setError("Please enter your email and password"); return; }
    setLoading(true); setError(null);
    try {
      const { createClient } = await import("https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm");
      const sb = createClient(import.meta.env.VITE_SUPABASE_URL, import.meta.env.VITE_SUPABASE_ANON_KEY);
      const { error: authError } = await sb.auth.signInWithPassword({ email, password });
      if(authError){ setError(authError.message); setLoading(false); }
      else { onLogin(); }
    } catch(e){ setError("Sign in failed. Please try again."); setLoading(false); }
  };

  return (
    <div style={{minHeight:"100vh",background:C.white,fontFamily:F,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
      <div style={{position:"absolute",inset:0,background:`radial-gradient(ellipse at 20% 50%,rgba(41,171,226,0.05) 0%,transparent 55%),radial-gradient(ellipse at 80% 20%,rgba(57,181,74,0.04) 0%,transparent 50%)`}}/>
      <div style={{width:"100%",maxWidth:420,position:"relative",zIndex:1}}>
        <div style={{textAlign:"center",marginBottom:36}}>
          <div style={{display:"inline-flex",marginBottom:10}}>
            <img src={LOGO_BLACK} alt="Fingoh" style={{height:44,display:"block"}}/>
          </div>
          <p style={{fontSize:12,color:C.muted,margin:0}}>Intent Intelligence · Exhibitor Edition</p>
        </div>
        <div style={{background:C.white,border:"1px solid #E2E8F0",borderRadius:16,padding:36,boxShadow:"0 4px 24px rgba(13,27,62,0.08)"}}>
          <h2 style={{fontSize:20,fontWeight:700,color:C.navy,marginBottom:4}}>Sign in</h2>
          <p style={{fontSize:12,color:C.muted,marginBottom:24}}>Exhibitor platform — know your buyers before they arrive</p>
          <div style={{marginBottom:14}}><label style={lD}>Work email</label><input value={email} onChange={e=>setEmail(e.target.value)} style={iD}/></div>
          <div style={{marginBottom:24}}><label style={lD}>Password</label><input type="password" value={password} onChange={e=>setPassword(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleSignIn()} style={iD}/></div>
          {error && <p style={{color:C.red,fontSize:12,marginBottom:12,textAlign:"center"}}>{error}</p>}
          <button onClick={handleSignIn} disabled={loading} style={{width:"100%",padding:13,background:loading?"#CBD5E1":C.blue,color:C.white,border:"none",borderRadius:8,fontSize:14,fontWeight:700,cursor:loading?"not-allowed":"pointer",fontFamily:F}}>
            {loading ? "Signing in..." : "Sign in →"}
          </button>
        </div>
      </div>
    </div>
  );
}

