// ── Context builders for each agent ──────────────────────────────
function buildAgentPrompt(agentId, item, ex) {
  const exhibitor  = ex?.company  || "the exhibitor";
  const product    = ex?.product  || "our solutions";
  const eventName  = ex?.name     || "the trade fair";
  const eventVenue = ex?.venue    || "";
  const eventAt    = eventVenue ? `${eventName} at ${eventVenue}` : eventName;

  if (agentId === "outreach") return `You are a B2B sales intelligence agent for ${exhibitor}, an exhibitor at ${eventAt}.

Write a short, highly personalised outreach email to ${item.visitor}, ${item.company}.
Their IEI intent score is ${item.ieiScore}/100 — they are a high-propensity prospect.
Role: ${item.role || "unknown"} | Industry: ${item.industry || "unknown"}
Context: ${item.reason}

The exhibitor's product: ${product}

Rules:
- Maximum 5 sentences
- Reference their specific company or role context in the first sentence
- Mention ${eventAt}
- Offer one specific hook (e.g. a relevant case study, a private demo, a framework pricing conversation)
- End with a single clear call to action
- Tone: direct, professional, no fluff — this is B2B procurement
- Do NOT start with "Dear" or "I hope this email finds you well"
- Output: subject line on first line, blank line, then email body only`;

  if (agentId === "routing") return `You are a live event sales routing agent for ${exhibitor} at ${eventAt}.

Generate a micro-brief for a sales staff member to approach ${item.visitor} from ${item.company} right now on the show floor.
Role: ${item.role || "unknown"} | IEI score: ${item.ieiScore}/100. Situation: ${item.reason}

Output exactly 3 lines:
Line 1: WHO — name, company, their role/buying context in one sentence
Line 2: WHAT THEY WANT — the specific need or buying signal detected
Line 3: OPEN WITH — the exact first sentence the staff member should say

Be specific. This is a real-time alert — the staff member has 10 seconds to read it before approaching.`;

  if (agentId === "followup") return `You are a post-event B2B follow-up agent for ${exhibitor}.

Draft a 3-touch follow-up sequence for ${item.visitor}, ${item.company}.
They are a top lead from ${eventAt}. IEI score: ${item.ieiScore}/100.
Role: ${item.role || "unknown"} | Industry: ${item.industry || "unknown"}
Context: ${item.reason}
Exhibitor product: ${product}

Output exactly:
EMAIL 1 (Day 1) — Subject line, then 4 sentences max. Personal, references the specific conversation.
---
LINKEDIN (Day 3) — 2 sentences. Short connection note, references event.
---
EMAIL 2 (Day 7) — Subject line, then 4 sentences max. Adds value — offer a relevant resource, case study, or next step.

Keep all 3 concise. B2B procurement audience — no fluff.`;

  return `Analyse this visitor and suggest the next best action for ${exhibitor}: ${JSON.stringify(item)}`;
}

// ═══════════════════════════════════════════════════════════════════
// AGENT PANEL COMPONENT
// ═══════════════════════════════════════════════════════════════════
function AgentPanel({ex, onClose, onQueueLoaded}) {
  const [activeAgent, setActiveAgent] = useState("outreach");
  const [queue, setQueue]             = useState([]);
  const [queueLoading, setQueueLoading] = useState(true);
  const [generating, setGenerating]   = useState({});
  const [outputs, setOutputs]         = useState({});
  const [approved, setApproved]       = useState({});
  const [dismissed, setDismissed]     = useState({});
  const [convNotes, setConvNotes]     = useState("");
  const [convAnalysis, setConvAnalysis] = useState(null);
  const [analysing, setAnalysing]     = useState(false);
  const [parsedDrafts, setParsedDrafts] = useState({});

  // ── Fetch real agent queue from backend ───────────────────────
  useEffect(() => {
    if (!ex?.id) { setQueueLoading(false); return; }
    (async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        const token = session?.access_token || "";
        const res = await fetch(`/api/v1/agent/queue?event_id=${ex.id}`, {
          headers: { "x-fingoh-auth": `Bearer ${token}` },
        });
        if (res.ok) {
          const data = await res.json();
          const q = data.queue || [];
          setQueue(q);
          // Pre-populate outputs with saved drafts
          const savedOutputs = {};
          const savedParsed  = {};
          q.forEach(item => {
            if (item.savedDraft?.text) {
              savedOutputs[item.id] = item.savedDraft.text;
              // Map camelCase for frontend display
              savedParsed[item.id] = {
                email1Subject: item.savedDraft.email1Subject,
                email1Body:    item.savedDraft.email1Body,
                linkedinText:  item.savedDraft.linkedinText,
                email2Subject: item.savedDraft.email2Subject,
                email2Body:    item.savedDraft.email2Body,
              };
            }
          });
          setOutputs(p => ({ ...p, ...savedOutputs }));
          setParsedDrafts(p => ({ ...p, ...savedParsed }));
          onQueueLoaded && onQueueLoaded(q.filter(i => !i.dismissed).length);
        }
      } catch (e) {
        console.error("Agent queue fetch failed:", e);
      } finally {
        setQueueLoading(false);
      }
    })();
  }, [ex?.id]);

  const agent  = AGENT_DEFS.find(a => a.id === activeAgent);
  const items  = queue.filter(q => q.agentId === activeAgent && !dismissed[q.id]);
  const pendingCount = queue.filter(q => !dismissed[q.id] && !approved[q.id]).length;

  // ── Generate agent output via Anthropic API ────────────────────
  const generate = async (item) => {
    if (generating[item.id]) return;
    setGenerating(p => ({ ...p, [item.id]: true }));
    setOutputs(p => ({ ...p, [item.id]: "" }));
    try {
      const prompt = buildAgentPrompt(item.agentId, item, ex);
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const res = await fetch("/api/v1/agent/generate", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-fingoh-auth": `Bearer ${token}`,
        },
        body: JSON.stringify({
          prompt,
          event_id:   ex?.id,
          contact_id: item.id,
          agent_id:   item.agentId,
        }),
      });
      const data = await res.json();
      const text = data.text || "No output generated.";
      setOutputs(p => ({ ...p, [item.id]: text }));
      // Map snake_case backend keys to camelCase for frontend
      const parsed = {
        email1Subject: data.email1_subject,
        email1Body:    data.email1_body,
        linkedinText:  data.linkedin_text,
        email2Subject: data.email2_subject,
        email2Body:    data.email2_body,
      };
      setParsedDrafts(p => ({ ...p, [item.id]: parsed }));
    } catch (e) {
      setOutputs(p => ({ ...p, [item.id]: "Error generating output. Please try again." }));
    } finally {
      setGenerating(p => ({ ...p, [item.id]: false }));
    }
  };

  // ── Conversation intelligence analysis ────────────────────────
  const analyseConversation = async () => {
    if (!convNotes.trim() || analysing) return;
    setAnalysing(true);
    setConvAnalysis(null);
    try {
      const prompt = `You are a real-time conversation intelligence agent at a B2B trade fair for ${ex?.company || "Siemens Healthineers"}.

A sales staff member just logged these conversation notes:
"${convNotes}"

Analyse the notes and respond in this exact JSON format:
{
  "missingSignals": ["signal 1", "signal 2", "signal 3"],
  "nextQuestion": "The single most impactful question to ask next",
  "intentScore": "rising|flat|declining",
  "scoreDelta": "+X or -X pts",
  "buyingSignals": ["any buying signals detected"],
  "redFlags": ["any concerns or negative signals"],
  "recommendation": "One specific next action for the sales person"
}

Be specific and actionable. Missing signals should be questions that, if asked, would significantly improve the IEI score for this visitor.`;

      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-opus-4-8",
          max_tokens: 500,
          messages: [{ role: "user", content: prompt }],
        }),
      });
      const data = await res.json();
      const text = data.content?.[0]?.text || "{}";
      const clean = text.replace(/```json|```/g, "").trim();
      try { setConvAnalysis(JSON.parse(clean)); }
      catch { setConvAnalysis({ recommendation: text, missingSignals: [], nextQuestion: "", scoreDelta: "", buyingSignals: [], redFlags: [] }); }
    } catch (e) {
      setConvAnalysis({ recommendation: "Analysis failed — check API connection.", missingSignals: [], nextQuestion: "", scoreDelta: "", buyingSignals: [], redFlags: [] });
    } finally {
      setAnalysing(false);
    }
  };

  const [sending, setSending] = useState({});
  const [sendResult, setSendResult] = useState({});

  const approve = async (item, emailNumber = 1) => {
    if (item.agentId === "routing") {
      setApproved(p => ({ ...p, [item.id]: true }));
      return;
    }
    if (!outputs[item.id]) {
      setApproved(p => ({ ...p, [item.id]: true }));
      return;
    }
    const sendKey = emailNumber === 2 ? item.id + "_2" : item.id;
    setSending(p => ({ ...p, [sendKey]: true }));
    try {
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const res = await fetch("/api/v1/agent/send", {
        method: "POST",
        headers: {
          "Content-Type":  "application/json",
          "x-fingoh-auth": `Bearer ${token}`,
        },
        body: JSON.stringify({
          event_id:       ex?.id,
          contact_id:     item.id,
          agent_id:       item.agentId,
          generated_text: outputs[item.id] || "",
          email_number:   emailNumber,
        }),
      });
      const data = await res.json();
      if (res.ok) {
        setSendResult(p => ({ ...p, [item.id]: { ok: true, to: data.to, subject: data.subject } }));
      } else {
        setSendResult(p => ({ ...p, [item.id]: { ok: false, error: data.detail || "Send failed" } }));
      }
    } catch(e) {
      setSendResult(p => ({ ...p, [item.id]: { ok: false, error: e.message } }));
    } finally {
      setSending(p => ({ ...p, [sendKey]: false }));
      if (emailNumber === 1) setApproved(p => ({ ...p, [item.id]: true }));
    }
  };
  const dismiss  = (id) => setDismissed(p => ({ ...p, [id]: true }));

  // ── Approval badge style ───────────────────────────────────────
  const approvalStyle = {
    required:   { bg:"#FEE2E2", tc:"#7F1D1D", label:"Requires approval" },
    "one-tap":  { bg:"#FEF9C3", tc:"#713F12", label:"One-tap approve"   },
    autonomous: { bg:"#DCFCE7", tc:"#14532D", label:"Autonomous"        },
  };

  return (
    <div style={{position:"fixed",inset:0,zIndex:200,display:"flex",alignItems:"flex-start",justifyContent:"flex-end",pointerEvents:"none"}}>
      {/* Backdrop */}
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(13,27,62,0.45)",backdropFilter:"blur(3px)",pointerEvents:"all"}}/>

      {/* Panel */}
      <div style={{position:"relative",width:520,height:"100vh",background:C.white,boxShadow:"-8px 0 40px rgba(0,0,0,0.18)",display:"flex",flexDirection:"column",pointerEvents:"all",overflowY:"hidden"}}>

        {/* Header */}
        <div style={{background:"linear-gradient(135deg,#0D1B3E 0%,#1A2A5E 60%,#263B7A 100%)",padding:"20px 22px 18px",flexShrink:0}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:14}}>
            <div>
              <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
                <div style={{width:28,height:28,borderRadius:8,background:"rgba(41,171,226,0.2)",border:"1px solid rgba(41,171,226,0.4)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14}}>✦</div>
                <span style={{fontSize:16,fontWeight:700,color:C.white,letterSpacing:"-0.01em"}}>Fingoh Agent</span>
                <span style={{fontSize:10,padding:"2px 7px",borderRadius:99,background:"rgba(57,181,74,0.2)",color:"#39B54A",border:"1px solid rgba(57,181,74,0.3)",fontWeight:600}}>LIVE</span>
              </div>
              <p style={{fontSize:11,color:"rgba(255,255,255,0.45)",margin:0}}>Agentic AI assistant · Claude Opus 4.8 · {ex?.company}</p>
            </div>
            <button onClick={onClose} style={{width:28,height:28,borderRadius:"50%",background:"rgba(255,255,255,0.1)",border:"1px solid rgba(255,255,255,0.15)",color:"rgba(255,255,255,0.6)",cursor:"pointer",fontSize:14,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>✕</button>
          </div>

          {/* Pending badge */}
          {pendingCount > 0 && (
            <div style={{background:"rgba(237,28,36,0.15)",border:"1px solid rgba(237,28,36,0.3)",borderRadius:9,padding:"7px 12px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{fontSize:11,color:"#FCA5A5"}}>{pendingCount} actions awaiting your review</span>
              <span style={{fontSize:11,fontWeight:700,color:C.red,background:"rgba(237,28,36,0.2)",padding:"1px 8px",borderRadius:99}}>{pendingCount}</span>
            </div>
          )}

          {/* Agent tabs */}
          <div style={{display:"flex",gap:5,marginTop:14,flexWrap:"wrap"}}>
            {AGENT_DEFS.map(a => {
              const pendingForAgent = queue.filter(q => q.agentId === a.id && !dismissed[q.id] && !approved[q.id]).length;
              return (
                <button key={a.id} onClick={() => setActiveAgent(a.id)}
                  style={{padding:"5px 10px",borderRadius:8,border:`1px solid ${activeAgent===a.id?a.color:"rgba(255,255,255,0.15)"}`,cursor:"pointer",background:activeAgent===a.id?`${a.color}25`:"rgba(255,255,255,0.05)",color:activeAgent===a.id?a.color:"rgba(255,255,255,0.5)",fontFamily:F,fontSize:10,fontWeight:600,display:"flex",alignItems:"center",gap:5,transition:"all .12s"}}>
                  <span>{a.icon}</span>{a.title.split(" ")[0]}
                  {pendingForAgent > 0 && <span style={{background:C.red,color:C.white,borderRadius:99,fontSize:9,padding:"0 5px",fontWeight:700}}>{pendingForAgent}</span>}
                </button>
              );
            })}
          </div>
        </div>

        {/* Agent info strip */}
        <div style={{padding:"12px 22px",background:`${agent.color}08`,borderBottom:`1px solid ${agent.color}20`,flexShrink:0}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div>
              <span style={{fontSize:13,fontWeight:700,color:agent.color}}>{agent.icon} {agent.title}</span>
              <p style={{fontSize:11,color:C.muted,margin:0,marginTop:2}}>{agent.tagline}</p>
            </div>
            <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:4}}>
              <span style={{fontSize:9,padding:"2px 7px",borderRadius:99,background:approvalStyle[agent.approval].bg,color:approvalStyle[agent.approval].tc,fontWeight:600}}>{approvalStyle[agent.approval].label}</span>
              <span style={{fontSize:9,color:C.muted2}}>{agent.persona} · {agent.phase}</span>
            </div>
          </div>
        </div>

        {/* Scrollable content */}
        <div style={{flex:1,overflowY:"auto",padding:"16px 22px"}}>

          {/* Queue items */}
          {(
            <div>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
                <p style={{fontSize:12,fontWeight:600,color:C.navy,margin:0}}>{items.length} action{items.length!==1?"s":""} pending</p>
                <p style={{fontSize:11,color:C.muted,margin:0}}>Trigger: {agent.trigger}</p>
              </div>

              {items.length === 0 && (
                <div style={{textAlign:"center",padding:"40px 20px",color:C.muted}}>
                  <div style={{fontSize:32,marginBottom:10}}>✦</div>
                  <p style={{fontSize:13,fontWeight:500,margin:0}}>All actions reviewed</p>
                  <p style={{fontSize:11,color:C.muted2,marginTop:4}}>No pending items for this agent</p>
                </div>
              )}

              {items.map(item => {
                const out    = outputs[item.id];
                const isGen  = generating[item.id];
                const isDone = approved[item.id];

                return (
                  <div key={item.id} style={{background:C.white,border:`1px solid ${isDone?C.green+"60":agent.color+"30"}`,borderRadius:14,overflow:"hidden",marginBottom:16,opacity:isDone?0.7:1,transition:"all .2s"}}>
                    {/* Item header */}
                    <div style={{padding:"12px 16px",background:isDone?C.ltgrn:`${agent.color}08`,borderBottom:`1px solid ${isDone?"#86EFAC":agent.color+"20"}`,display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                      <div>
                        <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:2}}>
                          <span style={{fontSize:13,fontWeight:700,color:isDone?"#14532D":C.dark}}>{item.visitor}</span>
                          {isDone && <span style={{fontSize:10,background:"#DCFCE7",color:"#14532D",padding:"1px 7px",borderRadius:99,fontWeight:700}}>✓ Approved</span>}
                        </div>
                        <p style={{fontSize:11,color:C.muted,margin:0}}>{item.company} · {item.country}</p>
                      </div>
                      <div style={{display:"flex",gap:6,alignItems:"center",flexShrink:0}}>
                        <span style={{fontSize:18,fontWeight:800,color:item.ieiScore>=75?C.green:C.blue}}>{item.ieiScore}</span>
                        <button onClick={() => dismiss(item.id)} style={{fontSize:10,color:C.muted2,background:"none",border:"none",cursor:"pointer",fontFamily:F}}>✕</button>
                      </div>
                    </div>

                    {/* Trigger reason */}
                    <div style={{padding:"8px 16px",borderBottom:`1px solid ${agent.color}15`,background:C.light}}>
                      <p style={{fontSize:11,color:C.muted,margin:0,fontStyle:"italic"}}>⚡ {item.reason}</p>
                    </div>

                    {/* Output area */}
                    <div style={{padding:"14px 16px"}}>
                      {!out && !isGen && (
                        <button onClick={() => generate(item)}
                          style={{width:"100%",padding:"10px 0",background:`linear-gradient(135deg,${agent.color},${agent.color}CC)`,color:C.white,border:"none",borderRadius:9,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F,display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
                          <span style={{fontSize:14}}>✦</span> Generate with Claude Opus 4.8
                        </button>
                      )}

                      {isGen && (
                        <div style={{textAlign:"center",padding:"16px 0"}}>
                          <div style={{fontSize:24,marginBottom:8,color:agent.color}}>◎</div>
                          <p style={{fontSize:12,color:C.muted,margin:0}}>Claude Opus 4.8 is drafting…</p>
                        </div>
                      )}

                      {out && !isGen && (() => {
                        const pd = parsedDrafts[item.id] || {};
                        const isFollowup = item.agentId === "followup";
                        const isRouting  = item.agentId === "routing";
                        return (
                        <div>
                          {/* Email 1 */}
                          {pd.email1Subject && (
                            <div style={{background:"#F8FAFC",border:"1px solid #E2E8F0",borderRadius:9,padding:14,marginBottom:10}}>
                              <p style={{fontSize:10,fontWeight:700,color:agent.color,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>
                                {isFollowup ? "Email 1 (Day 1)" : "Outreach Email"} · {pd.email1Subject}
                              </p>
                              <pre style={{fontSize:11,lineHeight:1.7,color:C.dark,margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{pd.email1Body}</pre>
                            </div>
                          )}

                          {/* LinkedIn card (followup only) */}
                          {isFollowup && pd.linkedinText && (
                            <div style={{background:"#EFF6FF",border:"1px solid #BFDBFE",borderRadius:9,padding:14,marginBottom:10}}>
                              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                                <p style={{fontSize:10,fontWeight:700,color:"#1D4ED8",textTransform:"uppercase",letterSpacing:.06,margin:0}}>LinkedIn (Day 3)</p>
                                <button onClick={() => navigator.clipboard.writeText(pd.linkedinText)}
                                  style={{fontSize:10,color:"#1D4ED8",background:"none",border:"1px solid #BFDBFE",borderRadius:5,padding:"2px 8px",cursor:"pointer",fontFamily:F}}>
                                  Copy
                                </button>
                              </div>
                              <pre style={{fontSize:11,lineHeight:1.7,color:"#1E3A8A",margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{pd.linkedinText}</pre>
                            </div>
                          )}

                          {/* Email 2 (followup only) */}
                          {isFollowup && pd.email2Subject && (
                            <div style={{background:"#F8FAFC",border:"1px solid #E2E8F0",borderRadius:9,padding:14,marginBottom:10}}>
                              <p style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>
                                Email 2 (Day 7) · {pd.email2Subject}
                              </p>
                              <pre style={{fontSize:11,lineHeight:1.7,color:C.dark,margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{pd.email2Body}</pre>
                            </div>
                          )}

                          {/* Fallback raw output for routing */}
                          {isRouting && (
                            <div style={{background:"#F8FAFC",border:"1px solid #E2E8F0",borderRadius:9,padding:14,marginBottom:10}}>
                              <p style={{fontSize:10,fontWeight:700,color:agent.color,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>Staff Brief</p>
                              <pre style={{fontSize:11,lineHeight:1.7,color:C.dark,margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{out}</pre>
                            </div>
                          )}

                          {/* Actions */}
                          {!isDone ? (
                            <div style={{display:"flex",flexDirection:"column",gap:8}}>
                              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                                <button onClick={() => approve(item)}
                                  style={{padding:"9px 0",background:C.green,color:C.white,border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
                                  {sending[item.id] ? "Sending…" : isRouting ? "✓ Approve Brief" : "✓ Send Email 1"}
                                </button>
                                <button onClick={() => generate(item)}
                                  style={{padding:"9px 0",background:C.white,color:C.navy,border:"1px solid #E2E8F0",borderRadius:8,fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:F}}>
                                  ↻ Regenerate
                                </button>
                              </div>
                              {isFollowup && pd.email2Subject && (
                                <button onClick={() => approve(item, 2)}
                                  style={{padding:"9px 0",background:"#1D4ED8",color:C.white,border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
                                  {sending[item.id + "_2"] ? "Sending…" : "✉ Send Email 2 (Day 7)"}
                                </button>
                              )}
                              <button onClick={() => dismiss(item.id)}
                                style={{padding:"7px 0",background:C.white,color:C.muted,border:"1px solid #E2E8F0",borderRadius:8,fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:F}}>
                                Dismiss
                              </button>
                            </div>
                          ) : (
                            <div style={{padding:"8px 12px",background:C.ltgrn,border:"1px solid #86EFAC",borderRadius:8,textAlign:"center",fontSize:12,fontWeight:600,color:"#14532D"}}>
                              {sendResult[item.id]?.ok
                                ? `✓ Email sent to ${sendResult[item.id].to}`
                                : sendResult[item.id]?.error
                                  ? `✗ ${sendResult[item.id].error}`
                                  : isRouting
                                    ? "✓ Brief approved — route to staff"
                                    : "✓ Email 1 sent"}
                            </div>
                          )}
                        </div>
                        );
                      })()}                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{padding:"10px 22px",borderTop:"1px solid #E2E8F0",background:"#FAFAFA",flexShrink:0,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <p style={{fontSize:10,color:C.muted2,margin:0}}>Powered by Claude Opus 4.8 · All actions require review before sending</p>
          <div style={{display:"flex",gap:4}}>
            {AGENT_DEFS.map(a => {
              const n = queue.filter(q => q.agentId === a.id && !dismissed[q.id] && !approved[q.id]).length;
              return n > 0 ? (
                <div key={a.id} style={{width:7,height:7,borderRadius:"50%",background:a.color}} title={`${n} pending — ${a.title}`}/>
              ) : null;
            })}
          </div>
        </div>
      </div>
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════════
// AGENT PAGE — Full screen agent intelligence hub
// ═══════════════════════════════════════════════════════════════════
function AgentPage({ ex, onQueueLoaded }) {
  const [activeAgent, setActiveAgent]     = useState("outreach");
  const [queue, setQueue]                 = useState([]);
  const [queueLoading, setQueueLoading]   = useState(true);
  const [generating, setGenerating]       = useState({});
  const [outputs, setOutputs]             = useState({});
  const [parsedDrafts, setParsedDrafts]   = useState({});
  const [approved, setApproved]           = useState({});
  const [dismissed, setDismissed]         = useState({});
  const [sending, setSending]             = useState({});
  const [sendResult, setSendResult]       = useState({});

  // ── Fetch queue on mount ───────────────────────────────────────
  useEffect(() => {
    if (!ex?.id) { setQueueLoading(false); return; }
    (async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        const token = session?.access_token || "";
        const res = await fetch(`/api/v1/agent/queue?event_id=${ex.id}`, {
          headers: { "x-fingoh-auth": `Bearer ${token}` },
        });
        if (res.ok) {
          const data = await res.json();
          const q = data.queue || [];
          setQueue(q);
          const savedOutputs = {};
          const savedParsed  = {};
          q.forEach(item => {
            if (item.savedDraft?.text) {
              savedOutputs[item.id] = item.savedDraft.text;
              savedParsed[item.id] = {
                email1Subject: item.savedDraft.email1Subject,
                email1Body:    item.savedDraft.email1Body,
                linkedinText:  item.savedDraft.linkedinText,
                email2Subject: item.savedDraft.email2Subject,
                email2Body:    item.savedDraft.email2Body,
              };
            }
          });
          setOutputs(savedOutputs);
          setParsedDrafts(savedParsed);
          onQueueLoaded && onQueueLoaded(q.length);
        }
      } catch(e) { console.error("Agent queue fetch failed:", e); }
      finally { setQueueLoading(false); }
    })();
  }, [ex?.id]);

  // ── Generate ───────────────────────────────────────────────────
  const generate = async (item) => {
    if (generating[item.id]) return;
    setGenerating(p => ({ ...p, [item.id]: true }));
    try {
      const prompt = buildAgentPrompt(item.agentId, item, ex);
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const res = await fetch("/api/v1/agent/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json", "x-fingoh-auth": `Bearer ${token}` },
        body: JSON.stringify({ prompt, event_id: ex?.id, contact_id: item.id, agent_id: item.agentId }),
      });
      const data = await res.json();
      setOutputs(p => ({ ...p, [item.id]: data.text || "" }));
      setParsedDrafts(p => ({ ...p, [item.id]: {
        email1Subject: data.email1_subject,
        email1Body:    data.email1_body,
        linkedinText:  data.linkedin_text,
        email2Subject: data.email2_subject,
        email2Body:    data.email2_body,
      }}));
    } catch(e) {
      setOutputs(p => ({ ...p, [item.id]: "Error generating output." }));
    } finally {
      setGenerating(p => ({ ...p, [item.id]: false }));
    }
  };

  // ── Send ───────────────────────────────────────────────────────
  const sendEmail = async (item, emailNumber = 1) => {
    if (item.agentId === "routing") { setApproved(p => ({ ...p, [item.id]: true })); return; }
    const sendKey = emailNumber === 2 ? item.id + "_2" : item.id;
    setSending(p => ({ ...p, [sendKey]: true }));
    try {
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const res = await fetch("/api/v1/agent/send", {
        method: "POST",
        headers: { "Content-Type": "application/json", "x-fingoh-auth": `Bearer ${token}` },
        body: JSON.stringify({
          event_id: ex?.id, contact_id: item.id, agent_id: item.agentId,
          generated_text: outputs[item.id] || "", email_number: emailNumber,
        }),
      });
      const data = await res.json();
      setSendResult(p => ({ ...p, [sendKey]: res.ok
        ? { ok: true, to: data.to, subject: data.subject }
        : { ok: false, error: data.detail || "Send failed" }
      }));
      if (emailNumber === 1) setApproved(p => ({ ...p, [item.id]: true }));
    } catch(e) {
      setSendResult(p => ({ ...p, [sendKey]: { ok: false, error: e.message } }));
    } finally {
      setSending(p => ({ ...p, [sendKey]: false }));
    }
  };

  const dismiss = (id) => setDismissed(p => ({ ...p, [id]: true }));

  const AGENT_DEFS = [
    { id:"outreach", icon:"📤", label:"Outreach",      color:"#7C3AED", desc:"High-intent prospects with no outreach yet" },
    { id:"routing",  icon:"🔥", label:"Hot Routing",   color:"#EA580C", desc:"Active on floor — route staff now"         },
    { id:"followup", icon:"✉️", label:"Follow-up",     color:"#0369A1", desc:"Completed meetings — send 3-touch sequence" },
  ];

  const activeAgentDef = AGENT_DEFS.find(a => a.id === activeAgent);
  const items = queue.filter(q => q.agentId === activeAgent && !dismissed[q.id]);
  const totalPending = queue.filter(q => !dismissed[q.id]).length;
  const totalSent = Object.values(sendResult).filter(r => r?.ok).length;

  return (
    <div style={{minHeight:"calc(100vh - 88px)",display:"flex",flexDirection:"column",background:"#F8FAFC",fontFamily:F}}>

      {/* Page header */}
      <div style={{background:"linear-gradient(135deg,#0D1B3E 0%,#1A2A5E 60%,#263B7A 100%)",padding:"24px 32px"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{width:36,height:36,borderRadius:10,background:"rgba(41,171,226,0.2)",border:"1px solid rgba(41,171,226,0.4)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>✦</div>
            <div>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <span style={{fontSize:20,fontWeight:800,color:"#fff",letterSpacing:"-0.02em"}}>Fingoh Agent</span>
                <span style={{fontSize:10,padding:"2px 8px",borderRadius:99,background:"rgba(57,181,74,0.2)",color:"#39B54A",border:"1px solid rgba(57,181,74,0.3)",fontWeight:700}}>LIVE</span>
              </div>
              <p style={{fontSize:12,color:"rgba(255,255,255,0.5)",margin:0}}>Agentic AI assistant · Claude Opus 4.8 · {ex?.company}</p>
            </div>
          </div>
          {/* Summary stats */}
          <div style={{display:"flex",gap:16}}>
            {[
              { label:"Pending",  value:totalPending,                color:"#FCD34D" },
              { label:"Sent",     value:totalSent,                   color:"#34D399" },
              { label:"Contacts", value:queue.length,                color:"#93C5FD" },
            ].map(s => (
              <div key={s.label} style={{textAlign:"center",padding:"8px 16px",background:"rgba(255,255,255,0.08)",borderRadius:10,border:"1px solid rgba(255,255,255,0.12)"}}>
                <div style={{fontSize:22,fontWeight:800,color:s.color,lineHeight:1}}>{s.value}</div>
                <div style={{fontSize:10,color:"rgba(255,255,255,0.5)",marginTop:2}}>{s.label}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Agent tabs */}
        <div style={{display:"flex",gap:10}}>
          {AGENT_DEFS.map(a => {
            const count = queue.filter(q => q.agentId === a.id && !dismissed[q.id]).length;
            const active = activeAgent === a.id;
            return (
              <button key={a.id} onClick={() => setActiveAgent(a.id)} style={{
                display:"flex",alignItems:"center",gap:8,padding:"10px 18px",
                background:active ? "#fff" : "rgba(255,255,255,0.08)",
                border:`1px solid ${active ? "#fff" : "rgba(255,255,255,0.15)"}`,
                borderRadius:10,cursor:"pointer",fontFamily:F,transition:"all .15s",
              }}>
                <span style={{fontSize:16}}>{a.icon}</span>
                <div style={{textAlign:"left"}}>
                  <div style={{fontSize:12,fontWeight:700,color:active ? a.color : "#fff"}}>{a.label}</div>
                  <div style={{fontSize:10,color:active ? "#64748B" : "rgba(255,255,255,0.5)"}}>{a.desc}</div>
                </div>
                {count > 0 && (
                  <span style={{marginLeft:4,minWidth:20,height:20,borderRadius:99,background:active ? a.color : "rgba(255,255,255,0.2)",color:"#fff",fontSize:10,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center",padding:"0 6px"}}>
                    {count}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Content area */}
      <div style={{flex:1,padding:"24px 32px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,alignItems:"start"}}>

        {queueLoading ? (
          <div style={{gridColumn:"1/-1",textAlign:"center",padding:"60px 0",color:"#94A3B8"}}>
            <div style={{fontSize:32,marginBottom:12}}>✦</div>
            <p style={{fontSize:14,fontWeight:500,margin:0}}>Loading agent queue…</p>
          </div>
        ) : items.length === 0 ? (
          <div style={{gridColumn:"1/-1",textAlign:"center",padding:"60px 0",color:"#94A3B8"}}>
            <div style={{fontSize:48,marginBottom:16}}>{activeAgentDef?.icon}</div>
            <p style={{fontSize:16,fontWeight:600,margin:"0 0 8px",color:"#475569"}}>No pending actions</p>
            <p style={{fontSize:13,margin:0}}>All {activeAgentDef?.label} items have been reviewed</p>
          </div>
        ) : items.map(item => {
          const pd      = parsedDrafts[item.id] || {};
          const out     = outputs[item.id];
          const isGen   = generating[item.id];
          const isDone  = approved[item.id];
          const isFollowup = item.agentId === "followup";
          const isRouting  = item.agentId === "routing";
          const sendKey2   = item.id + "_2";

          return (
            <div key={item.id} style={{background:"#fff",borderRadius:14,border:`1px solid ${isDone ? "#86EFAC" : activeAgentDef.color + "30"}`,overflow:"hidden",boxShadow:"0 1px 4px rgba(0,0,0,0.06)"}}>

              {/* Card header */}
              <div style={{padding:"14px 18px",background:isDone ? "#F0FDF4" : `${activeAgentDef.color}08`,borderBottom:`1px solid ${isDone ? "#86EFAC" : activeAgentDef.color + "20"}`,display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div>
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3}}>
                    <span style={{fontSize:14,fontWeight:700,color:isDone ? "#14532D" : "#0F172A"}}>{item.visitor}</span>
                    {isDone && <span style={{fontSize:10,background:"#DCFCE7",color:"#14532D",padding:"1px 7px",borderRadius:99,fontWeight:700}}>✓ Sent</span>}
                  </div>
                  <p style={{fontSize:11,color:"#64748B",margin:"0 0 2px"}}>{item.company}{item.role ? ` · ${item.role}` : ""}</p>
                  {item.industry && <p style={{fontSize:10,color:"#94A3B8",margin:0}}>{item.industry}</p>}
                </div>
                <div style={{display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
                  <span style={{fontSize:20,fontWeight:800,color:item.ieiScore >= 75 ? "#16A34A" : "#2563EB"}}>{typeof item.ieiScore === "number" ? item.ieiScore.toFixed(1) : item.ieiScore}</span>
                  <button onClick={() => dismiss(item.id)} style={{fontSize:12,color:"#94A3B8",background:"none",border:"none",cursor:"pointer",fontFamily:F,padding:4}}>✕</button>
                </div>
              </div>

              {/* Reason */}
              <div style={{padding:"8px 18px",background:"#F8FAFC",borderBottom:`1px solid ${activeAgentDef.color}15`}}>
                <p style={{fontSize:11,color:"#64748B",margin:0,fontStyle:"italic"}}>⚡ {item.reason}</p>
              </div>

              {/* Output area */}
              <div style={{padding:"16px 18px"}}>
                {!out && !isGen && (
                  <button onClick={() => generate(item)} style={{
                    width:"100%",padding:"11px 0",
                    background:`linear-gradient(135deg,${activeAgentDef.color},${activeAgentDef.color}CC)`,
                    color:"#fff",border:"none",borderRadius:9,fontSize:12,fontWeight:700,
                    cursor:"pointer",fontFamily:F,display:"flex",alignItems:"center",justifyContent:"center",gap:8,
                  }}>
                    <span>✦</span> Generate with Claude Opus 4.8
                  </button>
                )}

                {isGen && (
                  <div style={{textAlign:"center",padding:"20px 0"}}>
                    <div style={{fontSize:28,color:activeAgentDef.color,marginBottom:10}}>◎</div>
                    <p style={{fontSize:12,color:"#64748B",margin:0}}>Claude Opus 4.8 is drafting…</p>
                  </div>
                )}

                {out && !isGen && (
                  <div>
                    {/* Email 1 */}
                    {pd.email1Subject && (
                      <div style={{background:"#F8FAFC",border:"1px solid #E2E8F0",borderRadius:9,padding:14,marginBottom:10}}>
                        <p style={{fontSize:10,fontWeight:700,color:activeAgentDef.color,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>
                          {isFollowup ? "Email 1 (Day 1)" : "Outreach Email"} · {pd.email1Subject}
                        </p>
                        <pre style={{fontSize:11,lineHeight:1.7,color:"#0F172A",margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{pd.email1Body}</pre>
                      </div>
                    )}

                    {/* LinkedIn */}
                    {isFollowup && pd.linkedinText && (
                      <div style={{background:"#EFF6FF",border:"1px solid #BFDBFE",borderRadius:9,padding:14,marginBottom:10}}>
                        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                          <p style={{fontSize:10,fontWeight:700,color:"#1D4ED8",textTransform:"uppercase",letterSpacing:.06,margin:0}}>LinkedIn (Day 3)</p>
                          <button onClick={() => navigator.clipboard.writeText(pd.linkedinText)}
                            style={{fontSize:10,color:"#1D4ED8",background:"none",border:"1px solid #BFDBFE",borderRadius:5,padding:"2px 8px",cursor:"pointer",fontFamily:F}}>
                            Copy
                          </button>
                        </div>
                        <pre style={{fontSize:11,lineHeight:1.7,color:"#1E3A8A",margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{pd.linkedinText}</pre>
                      </div>
                    )}

                    {/* Email 2 */}
                    {isFollowup && pd.email2Subject && (
                      <div style={{background:"#F8FAFC",border:"1px solid #E2E8F0",borderRadius:9,padding:14,marginBottom:10}}>
                        <p style={{fontSize:10,fontWeight:700,color:"#64748B",textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>
                          Email 2 (Day 7) · {pd.email2Subject}
                        </p>
                        <pre style={{fontSize:11,lineHeight:1.7,color:"#0F172A",margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{pd.email2Body}</pre>
                      </div>
                    )}

                    {/* Routing brief */}
                    {isRouting && (
                      <div style={{background:"#FFF7ED",border:"1px solid #FED7AA",borderRadius:9,padding:14,marginBottom:10}}>
                        <p style={{fontSize:10,fontWeight:700,color:"#EA580C",textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>Staff Brief</p>
                        <pre style={{fontSize:11,lineHeight:1.7,color:"#0F172A",margin:0,whiteSpace:"pre-wrap",fontFamily:F}}>{out}</pre>
                      </div>
                    )}

                    {/* Action buttons */}
                    {!isDone ? (
                      <div style={{display:"flex",flexDirection:"column",gap:8,marginTop:4}}>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
                          <button onClick={() => sendEmail(item, 1)} style={{
                            padding:"10px 0",background:isDone ? "#94A3B8" : "#16A34A",
                            color:"#fff",border:"none",borderRadius:8,fontSize:12,fontWeight:700,
                            cursor:"pointer",fontFamily:F,
                          }}>
                            {sending[item.id] ? "Sending…" : isRouting ? "✓ Approve Brief" : "✉ Send Email 1"}
                          </button>
                          <button onClick={() => generate(item)} style={{
                            padding:"10px 0",background:"#fff",color:"#0F172A",
                            border:"1px solid #E2E8F0",borderRadius:8,fontSize:12,fontWeight:600,
                            cursor:"pointer",fontFamily:F,
                          }}>
                            ↻ Regenerate
                          </button>
                        </div>
                        {isFollowup && pd.email2Subject && (
                          <button onClick={() => sendEmail(item, 2)} style={{
                            padding:"10px 0",background:"#1D4ED8",color:"#fff",
                            border:"none",borderRadius:8,fontSize:12,fontWeight:700,
                            cursor:"pointer",fontFamily:F,
                          }}>
                            {sending[sendKey2] ? "Sending…" : "✉ Send Email 2 (Day 7)"}
                          </button>
                        )}
                        <button onClick={() => dismiss(item.id)} style={{
                          padding:"8px 0",background:"#fff",color:"#94A3B8",
                          border:"1px solid #E2E8F0",borderRadius:8,fontSize:11,fontWeight:600,
                          cursor:"pointer",fontFamily:F,
                        }}>
                          Dismiss
                        </button>
                      </div>
                    ) : (
                      <div style={{padding:"10px 14px",background:"#F0FDF4",border:"1px solid #86EFAC",borderRadius:8,fontSize:12,fontWeight:600,color:"#14532D"}}>
                        {sendResult[item.id]?.ok
                          ? `✓ Email 1 sent to ${sendResult[item.id].to}`
                          : sendResult[item.id]?.error
                            ? `✗ ${sendResult[item.id].error}`
                            : isRouting ? "✓ Brief approved" : "✓ Email 1 sent"}
                        {isFollowup && sendResult[sendKey2]?.ok && (
                          <div style={{marginTop:4,color:"#1D4ED8"}}>✓ Email 2 sent to {sendResult[sendKey2].to}</div>
                        )}
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}


// ── Agent trigger button — shown in nav ───────────────────────────
function AgentTriggerButton({onClick, queueCount}) {
  const [pulse, setPulse] = useState(false);
  useEffect(() => {
    const t = setInterval(() => setPulse(p => !p), 2000);
    return () => clearInterval(t);
  }, []);
  return (
    <button onClick={onClick}
      style={{padding:"5px 13px",borderRadius:7,border:`1px solid ${pulse?"rgba(41,171,226,0.6)":"rgba(41,171,226,0.3)"}`,cursor:"pointer",fontSize:11,fontWeight:700,background:pulse?"rgba(41,171,226,0.12)":"rgba(41,171,226,0.07)",color:C.blue,fontFamily:F,transition:"all .3s",display:"flex",alignItems:"center",gap:6}}>
      <span style={{fontSize:13}}>✦</span>
      Agent
      {queueCount > 0 && (
        <span style={{background:C.red,color:C.white,borderRadius:99,fontSize:9,padding:"1px 6px",fontWeight:700,minWidth:16,textAlign:"center"}}>{queueCount}</span>
      )}
    </button>
  );
}

// ═══════════════════════════════════════════════════════════════════
// EVENT SETUP SUMMARY
// ═══════════════════════════════════════════════════════════════════
function EventSetup({ex, onUpdate, onDelete}) {
  if (!ex) return null;

  const [editing, setEditing] = useState(false);
  const [saving, setSaving]   = useState(false);
  const [error, setError]     = useState(null);
  const [saved, setSaved]     = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);
  const [deleting, setDeleting] = useState(false);

  const [form, setForm] = useState({
    name: ex.name || "", venue: ex.venue || "", country: ex.country || "",
    dateFrom: ex.dateFrom || "", dateTo: ex.dateTo || "",
    company: ex.company || "", product: ex.product || "", website: ex.website || "", boothSize: ex.boothSize || "",
    cats: ex.cats || [],
    icpRole: ex.icpRole || [], icpSize: ex.icpSize || [], icpReason: ex.icpReason || [],
    intentWhy: ex.intentWhy || "", intentBuyers: ex.intentBuyers || "",
  });
  const upd = (k,v) => setForm(p=>({...p,[k]:v}));

  const startEdit = () => {
    setForm({
      name: ex.name || "", venue: ex.venue || "", country: ex.country || "",
      dateFrom: ex.dateFrom || "", dateTo: ex.dateTo || "",
      company: ex.company || "", product: ex.product || "", website: ex.website || "", boothSize: ex.boothSize || "",
      cats: ex.cats || [],
      icpRole: ex.icpRole || [], icpSize: ex.icpSize || [], icpReason: ex.icpReason || [],
      intentWhy: ex.intentWhy || "", intentBuyers: ex.intentBuyers || "",
    });
    setError(null);
    setEditing(true);
  };

  const cancelEdit = () => { setEditing(false); setError(null); };

  const saveEdit = async () => {
    setSaving(true); setError(null);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const headers = { "Content-Type":"application/json", "x-fingoh-auth": `Bearer ${token}` };

      // Update core event fields
      const coreRes = await fetch(`/api/proxy?slug=v1/events/${ex.id}`, {
        method: "PATCH", headers,
        body: JSON.stringify({
          name: form.name, venue: form.venue, country: form.country,
          date_from: form.dateFrom, date_to: form.dateTo,
          company: form.company, product: form.product, website: form.website, booth_size: form.boothSize,
        })
      });
      if (!coreRes.ok) throw new Error("Failed to save exhibition/company details");

      // Update targeting (categories, ICP, intent)
      const targetRes = await fetch(`/api/proxy?slug=v1/events/${ex.id}/targeting`, {
        method: "PATCH", headers,
        body: JSON.stringify({
          categories: form.cats,
          icp_roles: form.icpRole, icp_company_sizes: form.icpSize, icp_visit_reasons: form.icpReason,
          intent_why: form.intentWhy, intent_buyers: form.intentBuyers,
        })
      });
      if (!targetRes.ok) throw new Error("Failed to save targeting details");

      // Update local ex state via parent callback
      if (onUpdate) onUpdate({...ex, ...form});
      setEditing(false);
      setSaved(true); setTimeout(()=>setSaved(false), 2500);
    } catch (e) {
      setError(e.message || "Save failed — please try again");
    } finally {
      setSaving(false);
    }
  };

  const deleteEvent = async () => {
    setDeleting(true); setError(null);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const res = await fetch(`/api/proxy?slug=v1/events/${ex.id}`, {
        method: "DELETE",
        headers: { "x-fingoh-auth": `Bearer ${token}` }
      });
      if (!res.ok && res.status !== 204) throw new Error("Failed to delete event");
      if (onDelete) onDelete();
    } catch (e) {
      setError(e.message || "Delete failed — please try again");
      setDeleting(false);
    }
  };

  const Section = ({title, icon, children}) => (
    <div style={{background:C.white,border:"1px solid #E2E8F0",borderRadius:14,overflow:"hidden",marginBottom:16}}>
      <div style={{padding:"13px 20px",borderBottom:"1px solid #F1F5F9",background:"#FAFAFA",display:"flex",alignItems:"center",gap:9}}>
        <span style={{fontSize:16}}>{icon}</span>
        <span style={{fontSize:13,fontWeight:700,color:C.navy}}>{title}</span>
      </div>
      <div style={{padding:"16px 20px"}}>{children}</div>
    </div>
  );

  const Row = ({label, value}) => (
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",padding:"7px 0",borderBottom:"1px solid #F8FAFC"}}>
      <span style={{fontSize:11,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:.06,flexShrink:0,minWidth:140}}>{label}</span>
      <span style={{fontSize:12,color:C.dark,fontWeight:500,textAlign:"right",maxWidth:380,lineHeight:1.5}}>{value || <span style={{color:C.muted2,fontStyle:"italic"}}>Not set</span>}</span>
    </div>
  );

  const inputS = {width:"100%",maxWidth:380,padding:"7px 10px",border:"1px solid #E2E8F0",borderRadius:7,fontSize:12,fontFamily:F,outline:"none",boxSizing:"border-box",textAlign:"right"};

  const EditRow = ({label, value, onChange, type="text", placeholder}) => (
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 0",borderBottom:"1px solid #F8FAFC",gap:12}}>
      <span style={{fontSize:11,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:.06,flexShrink:0,minWidth:140}}>{label}</span>
      <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder||label} style={inputS}/>
    </div>
  );

  const TagRow = ({label, items, color=C.blue, bg=C.ltblue}) => (
    <div style={{padding:"7px 0",borderBottom:"1px solid #F8FAFC"}}>
      <span style={{fontSize:11,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:.06,display:"block",marginBottom:7}}>{label}</span>
      {items && items.length > 0
        ? <div style={{display:"flex",flexWrap:"wrap",gap:5}}>{items.map((t,i)=><span key={i} style={{fontSize:11,padding:"3px 10px",borderRadius:99,background:bg,color:color,fontWeight:500}}>{t}</span>)}</div>
        : <span style={{fontSize:11,color:C.muted2,fontStyle:"italic"}}>Not set</span>}
    </div>
  );

  const EditTagRow = ({label, items, onChange, color=C.blue, bg=C.ltblue}) => {
    const [draft, setDraft] = useState("");
    const addTag = () => { const v=draft.trim(); if(v && !items.includes(v)){ onChange([...items,v]); setDraft(""); } };
    const removeTag = (t) => onChange(items.filter(x=>x!==t));
    return (
      <div style={{padding:"7px 0",borderBottom:"1px solid #F8FAFC"}}>
        <span style={{fontSize:11,color:C.muted,fontWeight:600,textTransform:"uppercase",letterSpacing:.06,display:"block",marginBottom:7}}>{label}</span>
        <div style={{display:"flex",flexWrap:"wrap",gap:5,marginBottom:8}}>
          {items.map((t,i)=>(
            <span key={i} style={{fontSize:11,padding:"3px 6px 3px 10px",borderRadius:99,background:bg,color:color,fontWeight:500,display:"flex",alignItems:"center",gap:5}}>
              {t}
              <button onClick={()=>removeTag(t)} style={{background:"none",border:"none",cursor:"pointer",color:color,fontSize:13,lineHeight:1,padding:0}}>×</button>
            </span>
          ))}
        </div>
        <div style={{display:"flex",gap:6}}>
          <input value={draft} onChange={e=>setDraft(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"){e.preventDefault();addTag();}}}
            placeholder="Type and press Enter to add" style={{flex:1,padding:"6px 10px",border:"1px solid #E2E8F0",borderRadius:7,fontSize:12,fontFamily:F,outline:"none"}}/>
          <button onClick={addTag} style={{padding:"6px 14px",background:C.navy,color:C.white,border:"none",borderRadius:7,fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:F}}>+ Add</button>
        </div>
      </div>
    );
  };

  const signals = ex.intentSignals || [];
  const buyers  = ex.buyerSignals  || [];

  return (
    <div style={{padding:"28px 32px",maxWidth:860,margin:"0 auto",fontFamily:F}}>
      {/* Page header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:24}}>
        <div>
          <h1 style={{fontSize:22,fontWeight:800,color:C.navy,letterSpacing:"-0.02em",margin:0,marginBottom:4}}>Event setup</h1>
          <p style={{fontSize:13,color:C.muted,margin:0}}>Your configuration for <strong style={{color:C.navy}}>{ex.name}</strong> · Review or update at any time</p>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          {saved && <span style={{fontSize:12,color:C.green,fontWeight:600}}>✓ Saved</span>}
          {ex.isPast ? (
            <span style={{fontSize:11,padding:"5px 13px",borderRadius:99,background:"#F1F5F9",border:"1px solid #CBD5E1",color:C.muted,fontWeight:700}}>Past event · Read only</span>
          ) : (
            <span style={{fontSize:11,padding:"5px 13px",borderRadius:99,background:C.ltgrn,border:"1px solid #86EFAC",color:"#14532D",fontWeight:700}}>✓ Active</span>
          )}
          {ex.isPast ? null : !editing ? (
            <button onClick={startEdit}
              style={{padding:"8px 16px",background:C.navy,color:C.white,border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
              ✎ Edit
            </button>
          ) : (
            <div style={{display:"flex",gap:8}}>
              <button onClick={cancelEdit} disabled={saving}
                style={{padding:"8px 16px",background:C.white,color:C.muted,border:"1px solid #E2E8F0",borderRadius:8,fontSize:12,fontWeight:700,cursor:saving?"not-allowed":"pointer",fontFamily:F}}>
                Cancel
              </button>
              <button onClick={saveEdit} disabled={saving}
                style={{padding:"8px 16px",background:saving?"#94A3B8":C.green,color:C.white,border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:saving?"not-allowed":"pointer",fontFamily:F}}>
                {saving?"Saving…":"✓ Save changes"}
              </button>
            </div>
          )}
        </div>
      </div>

      {error && (
        <div style={{padding:"10px 14px",background:"#FEF2F2",border:"1px solid #FCA5A5",borderRadius:8,marginBottom:16}}>
          <p style={{fontSize:12,color:"#991B1B",margin:0}}>⚠ {error}</p>
        </div>
      )}

      {/* Exhibition details */}
      <Section title="Exhibition details" icon="🎪">
        {!editing ? (<>
          <Row label="Event name"   value={ex.name}/>
          <Row label="Type"         value={ex.type}/>
          <Row label="Dates"        value={ex.dateFrom && ex.dateTo ? `${ex.dateFrom} – ${ex.dateTo}` : null}/>
          <Row label="Venue"        value={ex.venue}/>
          <Row label="Country"      value={ex.country}/>
        </>) : (<>
          <EditRow label="Event name" value={form.name} onChange={v=>upd("name",v)}/>
          <Row label="Type" value={ex.type}/>
          <EditRow label="Start date" value={form.dateFrom} onChange={v=>upd("dateFrom",v)} type="date"/>
          <EditRow label="End date"   value={form.dateTo}   onChange={v=>upd("dateTo",v)}   type="date"/>
          <EditRow label="Venue"      value={form.venue}    onChange={v=>upd("venue",v)}/>
          <EditRow label="Country"    value={form.country}  onChange={v=>upd("country",v)}/>
        </>)}
      </Section>

      {/* Company & booth */}
      <Section title="Your company & booth" icon="🏢">
        {!editing ? (<>
          <Row label="Company"      value={ex.company}/>
          <Row label="Product / solution" value={ex.product}/>
          <Row label="Website"      value={ex.website}/>
          <Row label="Booth size"   value={ex.boothSize ? `${ex.boothSize} m²` : null}/>
        </>) : (<>
          <EditRow label="Company" value={form.company} onChange={v=>upd("company",v)}/>
          <EditRow label="Product / solution" value={form.product} onChange={v=>upd("product",v)}/>
          <EditRow label="Website" value={form.website} onChange={v=>upd("website",v)} placeholder="https://"/>
          <EditRow label="Booth size (m²)" value={form.boothSize} onChange={v=>upd("boothSize",v)}/>
        </>)}
      </Section>

      {/* Target categories */}
      <Section title="Target visitor categories" icon="🎯">
        {!editing ? (
          <TagRow label="Categories" items={ex.cats} color={C.blue} bg={C.ltblue}/>
        ) : (
          <EditTagRow label="Categories" items={form.cats} onChange={v=>upd("cats",v)} color={C.blue} bg={C.ltblue}/>
        )}
        <div style={{marginTop:10,padding:"9px 12px",background:C.ltnavy,borderRadius:8}}>
          <p style={{fontSize:11,color:C.muted,margin:0}}>Fingoh weights IEI scores higher for visitors with interests in these categories.</p>
        </div>
      </Section>

      {/* ICP */}
      <Section title="Ideal customer profile (ICP)" icon="🎖️">
        {!editing ? (<>
          <TagRow label="Target roles"          items={ex.icpRole}   color={C.navy}   bg={C.ltnavy}/>
          <TagRow label="Target company sizes"  items={ex.icpSize}   color={C.purple} bg={C.ltpur}/>
          <TagRow label="Visit reasons to attract" items={ex.icpReason} color={C.tealIEI} bg={C.tealLt}/>
        </>) : (<>
          <EditTagRow label="Target roles"          items={form.icpRole}   onChange={v=>upd("icpRole",v)}   color={C.navy}   bg={C.ltnavy}/>
          <EditTagRow label="Target company sizes"  items={form.icpSize}   onChange={v=>upd("icpSize",v)}   color={C.purple} bg={C.ltpur}/>
          <EditTagRow label="Visit reasons to attract" items={form.icpReason} onChange={v=>upd("icpReason",v)} color={C.tealIEI} bg={C.tealLt}/>
        </>)}
        <div style={{marginTop:10,padding:"9px 12px",background:C.ltnavy,borderRadius:8}}>
          <p style={{fontSize:11,color:C.muted,margin:0}}>These parameters define the <strong>Perfect / Good / Weak</strong> ICP tiers in the IEI scoring model.</p>
        </div>
      </Section>

      {/* Exhibitor intent */}
      <Section title="Your exhibitor intent" icon="✦">
        {!editing ? (<>
          {ex.intentWhy ? (
            <div style={{marginBottom:16}}>
              <p style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>Why you're attending</p>
              <p style={{fontSize:13,color:C.dark,lineHeight:1.7,padding:"12px 14px",background:C.light,borderRadius:8,margin:0}}>{ex.intentWhy}</p>
              {signals.length > 0 && (
                <div style={{marginTop:8,display:"flex",flexWrap:"wrap",gap:5}}>
                  {signals.map((s,i)=><span key={i} style={{fontSize:11,padding:"3px 10px",borderRadius:99,background:C.ltgrn,color:"#14532D",fontWeight:600}}>{s.icon} {s.label}</span>)}
                </div>
              )}
            </div>
          ) : <p style={{fontSize:12,color:C.muted2,fontStyle:"italic",marginBottom:16}}>No intent statement provided.</p>}

          {ex.intentBuyers ? (
            <div>
              <p style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>Visitors / buyers you want to meet</p>
              <p style={{fontSize:13,color:C.dark,lineHeight:1.7,padding:"12px 14px",background:C.light,borderRadius:8,margin:0}}>{ex.intentBuyers}</p>
              {buyers.length > 0 && (
                <div style={{marginTop:8,display:"flex",flexWrap:"wrap",gap:5}}>
                  {buyers.map((s,i)=><span key={i} style={{fontSize:11,padding:"3px 10px",borderRadius:99,background:C.ltblue,color:C.navy,fontWeight:600}}>{s.icon} {s.label}</span>)}
                </div>
              )}
            </div>
          ) : <p style={{fontSize:12,color:C.muted2,fontStyle:"italic"}}>No buyer profile provided.</p>}
        </>) : (<>
          <div style={{marginBottom:14}}>
            <p style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>Why you're attending</p>
            <textarea value={form.intentWhy} onChange={e=>upd("intentWhy",e.target.value)} rows={3}
              style={{width:"100%",padding:"10px 12px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontFamily:F,outline:"none",boxSizing:"border-box",resize:"vertical"}}/>
          </div>
          <div>
            <p style={{fontSize:10,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.06,marginBottom:6}}>Visitors / buyers you want to meet</p>
            <textarea value={form.intentBuyers} onChange={e=>upd("intentBuyers",e.target.value)} rows={3}
              style={{width:"100%",padding:"10px 12px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontFamily:F,outline:"none",boxSizing:"border-box",resize:"vertical"}}/>
          </div>
        </>)}

        <div style={{marginTop:14,padding:"9px 12px",background:`${C.purple}10`,border:`1px solid ${C.purple}30`,borderRadius:8}}>
          <p style={{fontSize:11,color:C.purple,margin:0,fontWeight:500}}>✦ Fingoh uses this intent statement to tune IEI scores, agent prompts, and live visitor alerts specifically for your goals.</p>
        </div>
      </Section>

      {/* Danger zone — delete event */}
      {!ex.isPast && (
      <div style={{background:"#FEF2F2",border:"1px solid #FCA5A5",borderRadius:14,padding:20,marginTop:24}}>
        <p style={{fontSize:13,fontWeight:700,color:"#991B1B",marginBottom:4}}>⚠ Danger zone</p>
        <p style={{fontSize:12,color:"#7F1D1D",marginBottom:14,lineHeight:1.6}}>Deleting this event archives it and removes it from your active events list. Visitor data and signals are preserved but no longer accessible from the dashboard.</p>
        {!confirmDelete ? (
          <button onClick={()=>setConfirmDelete(true)}
            style={{padding:"9px 18px",background:C.white,color:"#DC2626",border:"1.5px solid #DC2626",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
            🗑 Delete event
          </button>
        ) : (
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <span style={{fontSize:12,color:"#991B1B",fontWeight:600}}>Are you sure? This cannot be undone.</span>
            <button onClick={()=>setConfirmDelete(false)} disabled={deleting}
              style={{padding:"8px 16px",background:C.white,color:C.muted,border:"1px solid #E2E8F0",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
              Cancel
            </button>
            <button onClick={deleteEvent} disabled={deleting}
              style={{padding:"8px 16px",background:"#DC2626",color:C.white,border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:deleting?"not-allowed":"pointer",fontFamily:F}}>
              {deleting?"Deleting…":"Yes, delete permanently"}
            </button>
          </div>
        )}
      </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════
// MEETING RESPONSE PAGE — public page for accept/decline links
// ═══════════════════════════════════════════════════════════════════
function MeetingResponsePage({token}) {
  const [status, setStatus]   = useState("loading"); // loading|success|error|already
  const [action, setAction]   = useState(null);
  const [meeting, setMeeting] = useState(null);
  const [error, setError]     = useState(null);

  React.useEffect(()=>{
    if (!token) { setStatus("error"); setError("Invalid link — no token found."); return; }
    // Call the public respond endpoint
    fetch(`/api/proxy?slug=v1/meetings/respond/${token}`)
      .then(r => r.json())
      .then(data => {
        if (data.detail) throw new Error(data.detail);
        setAction(data.action);
        setMeeting(data.meeting);
        setStatus(data.status === "already_responded" ? "already" : "success");
      })
      .catch(e => { setStatus("error"); setError(e.message || "Something went wrong"); });
  },[token]);

  const F = "'DM Sans', system-ui, sans-serif";
  const navy = "#0D1B3E";

  if (status === "loading") return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:F,background:"#F8FAFC"}}>
      <div style={{textAlign:"center"}}>
        <div style={{width:40,height:40,border:"3px solid #E2E8F0",borderTopColor:navy,borderRadius:"50%",animation:"spin 1s linear infinite",margin:"0 auto 16px"}}/>
        <p style={{color:"#64748B",fontSize:14}}>Processing your response…</p>
      </div>
    </div>
  );

  if (status === "error") return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:F,background:"#F8FAFC"}}>
      <div style={{textAlign:"center",maxWidth:400,padding:32}}>
        <div style={{fontSize:48,marginBottom:16}}>⚠️</div>
        <h2 style={{fontSize:20,fontWeight:700,color:navy,marginBottom:8}}>Link Error</h2>
        <p style={{color:"#64748B",lineHeight:1.6}}>{error || "This link is invalid or has expired."}</p>
      </div>
    </div>
  );

  if (status === "already") return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:F,background:"#F8FAFC"}}>
      <div style={{textAlign:"center",maxWidth:400,padding:32}}>
        <div style={{fontSize:48,marginBottom:16}}>✅</div>
        <h2 style={{fontSize:20,fontWeight:700,color:navy,marginBottom:8}}>Already Responded</h2>
        <p style={{color:"#64748B",lineHeight:1.6}}>You have already responded to this meeting request.</p>
      </div>
    </div>
  );

  const accepted = action === "accept";
  const dt = meeting?.proposed_datetime;
  let dtFmt = dt;
  try { dtFmt = new Date(dt).toLocaleString("en-IN", {weekday:"long",day:"numeric",month:"long",year:"numeric",hour:"2-digit",minute:"2-digit"}); } catch {}

  return (
    <div style={{minHeight:"100vh",background:"#F8FAFC",fontFamily:F,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
      <div style={{maxWidth:480,width:"100%"}}>
        {/* Header */}
        <div style={{background:navy,borderRadius:"14px 14px 0 0",padding:"24px 28px",textAlign:"center"}}>
          <img src="/Fingoh_White.png" alt="Fingoh" style={{height:28,marginBottom:12}} onError={e=>{e.target.style.display="none"}}/>
          <h1 style={{color:"white",fontSize:22,fontWeight:800,margin:0}}>
            {accepted ? "✓ Meeting Confirmed!" : "Meeting Declined"}
          </h1>
        </div>

        {/* Body */}
        <div style={{background:"white",border:"1px solid #E2E8F0",borderTop:"none",padding:"28px",borderRadius:"0 0 14px 14px"}}>
          <div style={{textAlign:"center",marginBottom:24}}>
            <div style={{fontSize:56,marginBottom:12}}>{accepted ? "🤝" : "👋"}</div>
            <p style={{fontSize:15,color:"#475569",lineHeight:1.6}}>
              {accepted
                ? "Thank you for confirming! The exhibitor will be in touch with final details."
                : "No problem — we've let the exhibitor know you won't be able to make this meeting."}
            </p>
          </div>

          {/* Meeting details */}
          {meeting && accepted && (
            <div style={{background:"#F8FAFC",border:"1px solid #E2E8F0",borderRadius:10,padding:"16px 18px",marginBottom:20}}>
              <p style={{fontSize:11,fontWeight:700,color:"#94A3B8",textTransform:"uppercase",letterSpacing:.08,marginBottom:10}}>Meeting Details</p>
              {dtFmt && <div style={{display:"flex",gap:10,marginBottom:7}}><span style={{fontSize:14}}>📅</span><span style={{fontSize:13,color:"#1E293B"}}>{dtFmt}</span></div>}
              {meeting.duration_minutes && <div style={{display:"flex",gap:10,marginBottom:7}}><span style={{fontSize:14}}>⏱</span><span style={{fontSize:13,color:"#1E293B"}}>{meeting.duration_minutes} minutes</span></div>}
              {meeting.location && <div style={{display:"flex",gap:10,marginBottom:7}}><span style={{fontSize:14}}>📍</span><span style={{fontSize:13,color:"#1E293B"}}>{meeting.location}</span></div>}
              {meeting.topic && <div style={{display:"flex",gap:10}}><span style={{fontSize:14}}>💬</span><span style={{fontSize:13,color:"#1E293B"}}>{meeting.topic}</span></div>}
            </div>
          )}

          <div style={{textAlign:"center",padding:"14px",background:accepted?"#F0FDF4":"#FEF2F2",borderRadius:8,border:`1px solid ${accepted?"#86EFAC":"#FCA5A5"}`}}>
            <p style={{fontSize:12,color:accepted?"#14532D":"#991B1B",margin:0,fontWeight:500}}>
              {accepted
                ? "A calendar invite will be sent to your email shortly."
                : "Feel free to reach out if you'd like to reschedule."}
            </p>
          </div>

          <p style={{textAlign:"center",fontSize:11,color:"#94A3B8",marginTop:20,margin:"20px 0 0 0"}}>
            Powered by Fingoh · AI-powered trade fair intelligence
          </p>
        </div>
      </div>
    </div>
  );
}

// UserMenu component
function UserMenu({ profile } = {}) {
  const userInitial = (profile?.name || profile?.org_name || "U")[0].toUpperCase();
  const [open, setOpen]           = useState(false);
  const [showProfile, setShowProfile] = useState(false);
  const [userName, setUserName]   = useState(profile?.name || "");
  const [pw, setPw]               = useState({n:"", c:""});
  const [err, setErr]             = useState("");
  const [ok, setOk]               = useState(false);
  const [nameOk, setNameOk]       = useState(false);
  const [loading, setLoading]     = useState(false);
  const [showPwSection, setShowPwSection] = useState(false);

  // Sync name when profile loads
  React.useEffect(() => {
    if (profile?.name) setUserName(profile.name);
  }, [profile?.name]);

  const saveName = async () => {
    const nameErr = V.name(userName);
    if (nameErr) { setErr(nameErr); return; }
    setLoading(true); setErr("");
    try {
      const { data: { session } } = await supabase.auth.getSession();
      const token = session?.access_token || "";
      const res = await fetch("/api/v1/onboarding/me", {
        method: "PATCH",
        headers: { "Content-Type": "application/json", "x-fingoh-auth": `Bearer ${token}` },
        body: JSON.stringify({ name: userName.trim() }),
      });
      if (!res.ok) throw new Error("Failed to update name");
      setNameOk(true);
      setTimeout(() => setNameOk(false), 2000);
    } catch(e) { setErr(e.message); }
    setLoading(false);
  };

  const savePw = async () => {
    if (pw.n !== pw.c) { setErr("Passwords do not match"); return; }
    if (pw.n.length < 8) { setErr("Min 8 characters"); return; }
    setLoading(true); setErr("");
    const { error } = await supabase.auth.updateUser({ password: pw.n });
    if (error) setErr(error.message);
    else { setOk(true); setTimeout(()=>{ setOk(false); setPw({n:"",c:""}); setShowPwSection(false); },2000); }
    setLoading(false);
  };

  const ReadRow = ({label, value}) => (
    <div style={{marginBottom:12}}>
      <p style={{fontSize:10,fontWeight:600,color:"#94A3B8",textTransform:"uppercase",letterSpacing:.06,margin:"0 0 3px"}}>{label}</p>
      <p style={{fontSize:13,color:"#0F172A",margin:0,fontWeight:500}}>{value || "—"}</p>
    </div>
  );

  return (
    <div style={{position:"relative",display:"inline-block"}}>
      <button onClick={()=>setOpen(o=>!o)}
        style={{display:"flex",alignItems:"center",gap:6,padding:"4px 10px",borderRadius:7,border:"1px solid #E2E8F0",cursor:"pointer",background:"transparent",fontSize:11,fontWeight:600,color:"#475569",fontFamily:F}}>
        <div style={{width:22,height:22,borderRadius:"50%",background:"#0D1B3E",color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700}}>{userInitial}</div>
        <span>▾</span>
      </button>

      {open && (
        <div style={{position:"absolute",top:"110%",right:0,marginTop:4,background:"#fff",border:"1px solid #E2E8F0",borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,0.12)",zIndex:1000,minWidth:180,overflow:"hidden"}} onClick={()=>setOpen(false)}>
          <button onClick={(e)=>{e.stopPropagation(); setOpen(false); setShowProfile(true);}}
            style={{width:"100%",padding:"11px 16px",background:"none",border:"none",textAlign:"left",fontSize:12,color:"#1E293B",cursor:"pointer",fontFamily:F,display:"flex",alignItems:"center",gap:8}}>
            <span>👤</span> Profile settings
          </button>
          <div style={{height:1,background:"#F1F5F9"}}/>
          <button onClick={()=>supabase.auth.signOut()}
            style={{width:"100%",padding:"11px 16px",background:"none",border:"none",textAlign:"left",fontSize:12,color:"#DC2626",cursor:"pointer",fontFamily:F,display:"flex",alignItems:"center",gap:8}}>
            <span>↪</span> Sign out
          </button>
        </div>
      )}

      {/* Profile Settings Modal */}
      {showProfile && (
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.45)",zIndex:2000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={()=>setShowProfile(false)}>
          <div style={{background:"#fff",borderRadius:16,padding:28,maxWidth:400,width:"100%",boxShadow:"0 20px 60px rgba(0,0,0,0.2)"}} onClick={e=>e.stopPropagation()}>

            {/* Header */}
            <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:24}}>
              <div style={{width:48,height:48,borderRadius:"50%",background:"#0D1B3E",color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,fontWeight:700,flexShrink:0}}>
                {userInitial}
              </div>
              <div>
                <h3 style={{fontSize:16,fontWeight:700,color:"#0D1B3E",margin:"0 0 2px"}}>{profile?.name || "Your Profile"}</h3>
                <p style={{fontSize:12,color:"#64748B",margin:0}}>{profile?.org_name || "—"}</p>
              </div>
              <button onClick={()=>setShowProfile(false)} style={{marginLeft:"auto",background:"none",border:"none",fontSize:18,color:"#94A3B8",cursor:"pointer"}}>✕</button>
            </div>

            {/* Read-only fields */}
            <ReadRow label="Email" value={profile?.email || "—"} />
            <ReadRow label="Company" value={profile?.org_name || "—"} />
            <ReadRow label="Role" value={profile?.role || "—"} />

            {/* Editable name */}
            <div style={{marginBottom:16}}>
              <p style={{fontSize:10,fontWeight:600,color:"#94A3B8",textTransform:"uppercase",letterSpacing:.06,margin:"0 0 5px"}}>Display name</p>
              <div style={{display:"flex",gap:8}}>
                <input value={userName} onChange={e=>setUserName(e.target.value)}
                  style={{flex:1,padding:"9px 12px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontFamily:F,outline:"none",color:"#0F172A"}}/>
                <button onClick={saveName} disabled={loading}
                  style={{padding:"9px 16px",background:nameOk?"#16A34A":"#0D1B3E",color:"#fff",border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F,whiteSpace:"nowrap"}}>
                  {nameOk ? "✓ Saved" : loading ? "…" : "Save"}
                </button>
              </div>
            </div>

            <div style={{height:1,background:"#F1F5F9",margin:"16px 0"}}/>

            {/* Change password toggle */}
            <button onClick={()=>{setShowPwSection(s=>!s); setErr(""); setOk(false);}}
              style={{width:"100%",padding:"9px 0",background:"#F8FAFC",border:"1px solid #E2E8F0",borderRadius:8,fontSize:12,fontWeight:600,color:"#475569",cursor:"pointer",fontFamily:F,marginBottom:showPwSection?12:0}}>
              {showPwSection ? "▲ Hide" : "🔒 Change password"}
            </button>

            {showPwSection && (
              <div style={{display:"flex",flexDirection:"column",gap:10}}>
                <input type="password" placeholder="New password (min 8 chars)" value={pw.n} onChange={e=>setPw(p=>({...p,n:e.target.value}))}
                  style={{padding:"9px 12px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontFamily:F,outline:"none"}}/>
                <input type="password" placeholder="Confirm new password" value={pw.c} onChange={e=>setPw(p=>({...p,c:e.target.value}))}
                  style={{padding:"9px 12px",border:"1px solid #E2E8F0",borderRadius:8,fontSize:13,fontFamily:F,outline:"none"}}/>
                {err && <p style={{color:"#DC2626",fontSize:12,margin:0}}>{err}</p>}
                {ok  && <p style={{color:"#16A34A",fontSize:12,margin:0,fontWeight:600}}>✓ Password updated!</p>}
                <button onClick={savePw} disabled={loading}
                  style={{padding:"9px 0",background:loading?"#CBD5E1":"#0D1B3E",color:"#fff",border:"none",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:F}}>
                  {loading ? "Updating…" : "Update password"}
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════════
// NAV SHELL
// ═══════════════════════════════════════════════════════════════════
function NavShell({screen, onNav, ex, children, onAgent, agentCount=0, onBackToEvents, profile}) {
  const isPast = !!ex?.isPast;

  const PHASES = [
    {
      id:"pre",
      label:"Pre-event",
      color:"#7C3AED",
      bg:"#F5F3FF",
      border:"#DDD6FE",
      items: isPast ? [
        {id:"iei",         label:"IEI Analysis",     icon:"◎"},
        {id:"meetings",    label:"Meetings",          icon:"🤝"},
      ] : [
        {id:"audience",    label:"Audience Upload",  icon:"⬆"},
        {id:"iei",         label:"IEI Analysis",     icon:"◎"},
        {id:"meetings",    label:"Meetings",          icon:"🤝"},
      ]
    },
    {
      id:"during",
      label:"During Event",
      color:C.tealIEI,
      bg:C.tealLt,
      border:"#99F6E4",
      items: isPast ? [
        {id:"live",        label:"Live Dashboard",   icon:"◉"},
        {id:"agent",       label:"Fingoh Agent",     icon:"✦"},
      ] : [
        {id:"live",        label:"Live Dashboard",   icon:"◉"},
        {id:"staff",       label:"Staff App",        icon:"📱"},
        {id:"agent",       label:"Fingoh Agent",     icon:"✦"},
      ]
    },
    {
      id:"post",
      label:"Post-event",
      color:C.navy,
      bg:C.ltnavy,
      border:"#C7D0E8",
      items:[
        {id:"outcomes",    label:"Outcomes",         icon:"📊"},
        {id:"export",      label:"Export Leads",     icon:"↑"},
        {id:"event-setup", label:"Event Setup",      icon:"⚙️"},
      ]
    },
  ];

  const allItems = PHASES.flatMap(p=>p.items);
  const activePhase = PHASES.find(p=>p.items.some(i=>i.id===screen));

  return (
    <div style={{minHeight:"100vh",background:C.light,fontFamily:F}}>
      {/* Top bar */}
      <div style={{background:C.white,borderBottom:"1px solid #E2E8F0",position:"sticky",top:0,zIndex:50}}>
        {/* Row 1 — logo + event info + agent */}
        <div style={{height:48,display:"flex",alignItems:"center",padding:"0 24px",borderBottom:"1px solid #F1F5F9"}}>
          <div style={{display:"flex",alignItems:"center",gap:8,marginRight:14}}>
            <img src={LOGO_BLACK} alt="Fingoh" style={{height:22,display:"block"}}/>
            <span style={{fontSize:10,padding:"2px 7px",borderRadius:99,background:C.ltblue,color:C.blue,fontWeight:600}}>Exhibitor</span>
          </div>
          <button onClick={onBackToEvents}
            style={{display:"flex",alignItems:"center",gap:5,padding:"4px 10px",marginRight:16,borderRadius:7,border:"1px solid #E2E8F0",cursor:"pointer",background:"transparent",fontSize:11,fontWeight:600,color:C.muted,fontFamily:F,flexShrink:0,whiteSpace:"nowrap"}}
            onMouseOver={e=>{e.currentTarget.style.background=C.light;e.currentTarget.style.color=C.navy;}}
            onMouseOut={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color=C.muted;}}>
            ← Events
          </button>
          <div style={{flex:1,display:"flex",alignItems:"center",gap:6}}>
            <span style={{fontSize:11,fontWeight:700,color:C.navy,maxWidth:260,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{ex?.name}</span>
            <span style={{fontSize:11,color:C.muted2}}>·</span>
            <span style={{fontSize:11,color:C.muted}}>{ex?.company}</span>
            {activePhase && (
              <span style={{fontSize:10,padding:"2px 9px",borderRadius:99,background:activePhase.bg,color:activePhase.color,fontWeight:700,border:`1px solid ${activePhase.border}`,marginLeft:6}}>
                {activePhase.label}
              </span>
            )}
          </div>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <AgentTriggerButton onClick={()=>onNav("agent")} queueCount={agentCount}/>
            {isPast ? (
              <span style={{display:"flex",alignItems:"center",gap:5,padding:"4px 10px",background:"#F1F5F9",borderRadius:99,border:"1px solid #CBD5E1",fontSize:10,fontWeight:700,color:C.muted}}>
                <span style={{width:5,height:5,borderRadius:"50%",background:"#94A3B8",display:"inline-block"}}/>Past event · Read only
              </span>
            ) : (
              <span style={{display:"flex",alignItems:"center",gap:5,padding:"4px 10px",background:C.ltgrn,borderRadius:99,border:"1px solid #86EFAC",fontSize:10,fontWeight:700,color:"#14532D"}}>
                <span style={{width:5,height:5,borderRadius:"50%",background:"#16A34A",display:"inline-block"}}/>LIVE · Day 2
              </span>
            )}
            <div style={{width:1,height:20,background:"#E2E8F0",margin:"0 8px"}}/>
            <UserMenu profile={profile}/>
          </div>
        </div>

        {/* Row 2 — phase-grouped nav */}
        <div style={{height:40,display:"flex",alignItems:"stretch",padding:"0 24px",gap:0}}>
          {PHASES.map((phase,pi)=>(
            <div key={phase.id} style={{display:"flex",alignItems:"center",gap:0,marginRight:pi<PHASES.length-1?24:0}}>
              {/* Phase label */}
              <span style={{fontSize:9,fontWeight:700,color:C.muted2,textTransform:"uppercase",letterSpacing:.12,paddingRight:8,flexShrink:0,borderRight:`1px solid #E2E8F0`,marginRight:6,lineHeight:"40px"}}>
                {phase.label}
              </span>
              {/* Items */}
              {phase.items.map(item=>{
                const active = screen===item.id;
                return (
                  <button key={item.id} onClick={()=>onNav(item.id)}
                    style={{
                      display:"flex",alignItems:"center",gap:5,
                      padding:"0 11px",height:"100%",
                      border:"none",borderBottom:`2px solid ${active?phase.color:"transparent"}`,
                      cursor:"pointer",fontSize:11,fontWeight:active?700:500,
                      background:active?`${phase.color}08`:"transparent",
                      color:active?phase.color:C.muted,
                      fontFamily:F,transition:"all .12s",whiteSpace:"nowrap",
                    }}>
                    <span style={{fontSize:12}}>{item.icon}</span> {item.label}
                  </button>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <div>{children}</div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════
// ROOT
// ═══════════════════════════════════════════════════════════════════
  export default function App() {
  const [screen, setScreen]     = useState(()=>{
    try { return sessionStorage.getItem("fingoh_screen") || "login"; } catch { return "login"; }
  });
  const [ex, setEx]             = useState(()=>{
    try {
      const saved = sessionStorage.getItem("fingoh_ex");
      return saved ? JSON.parse(saved) : null;
    } catch { return null; }
  });

  // Past events are read-only — redirect away from upload/staff screens
  React.useEffect(()=>{
    if (ex?.isPast) {
      if (screen === "audience") setScreen("iei");
      if (screen === "staff") setScreen("live");
    }
  }, [ex?.isPast, screen]);

  // Persist screen + ex to sessionStorage on every change
  React.useEffect(()=>{
    try { sessionStorage.setItem("fingoh_screen", screen); } catch {}
  }, [screen]);
  React.useEffect(()=>{
    try {
      if (ex) sessionStorage.setItem("fingoh_ex", JSON.stringify(ex));
      else sessionStorage.removeItem("fingoh_ex");
    } catch {}
  }, [ex]);
  const [selP, setSelP]         = useState(null);
  const [agentOpen, setAgentOpen] = useState(false);

  // Real auth state
  const [authUser, setAuthUser]   = useState(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [profile, setProfile]     = useState(null);

  // Init auth on mount
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setAuthUser(session?.user ?? null)
      setAuthLoading(false)
      if (session?.user) {
        getMyProfile().then(setProfile).catch(() => {})
        // Only go to events if currently on login screen — preserve current screen
        setScreen(prev => prev === "login" ? "events" : prev)
      } else {
        setScreen("login")
      }
    })

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setAuthUser(session?.user ?? null)
      if (session?.user) {
        getMyProfile().then(setProfile).catch(() => {})
        // Only redirect to events on actual sign-in, not on token refresh
        setScreen(prev => prev === "login" ? "events" : prev)
      } else {
        setScreen("login")
        setProfile(null)
      }
    })

    return () => subscription.unsubscribe()
  }, [])

  const [agentQueueCount, setAgentQueueCount] = useState(0)

  // Registration page — public, no auth needed
  const regParams = new URLSearchParams(window.location.search);
  const regEventId = regParams.get("register");
  if (regEventId) {
    return <RegistrationPage eventId={regEventId}/>;
  }

// ═══════════════════════════════════════════════════════════════════
// PUBLIC REGISTRATION PAGE
// Accessible at: fingoh-exhibitor.vercel.app?register=EVENT_ID
// No auth required — shareable link for exhibitors to send to buyers
// ═══════════════════════════════════════════════════════════════════
function RegistrationPage({ eventId }) {
  const F = "'DM Sans', system-ui, sans-serif";
  const navy = "#0D1B3E";

  const [eventInfo, setEventInfo] = React.useState(null);
  const [loading,   setLoading]   = React.useState(true);
  const [step,      setStep]      = React.useState(1); // 1=details, 2=intent, 3=success
  const [saving,      setSaving]      = React.useState(false);
  const [error,       setError]       = React.useState("");
  const [result,      setResult]      = React.useState(null);
  const [fErrors,     setFErrors]     = React.useState({});
  const [emailChecking, setEmailChecking] = React.useState(false);
  const [emailStatus,   setEmailStatus]   = React.useState(null); // null | "new" | "registered" | "exists"
  
  const checkEmail = async (email) => {
    if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email)) return;
    setEmailChecking(true);
    try {
      const res = await fetch(`/api/v1/audience/register/${eventId}/check-email?email=${encodeURIComponent(email)}`);
      const data = await res.json();
      if (data.already_registered) {
        setEmailStatus("registered");
        setFErrors(fe => ({...fe, email: `${data.name || "This person"} is already registered for this event.`}));
      } else if (data.exists) {
        setEmailStatus("exists");
        setFErrors(fe => ({...fe, email: null})); // In our system but not registered — fine
      } else {
        setEmailStatus("new");
        setFErrors(fe => ({...fe, email: null}));
      }
    } catch(e) { /* silent fail */ }
    setEmailChecking(false);
  };

  const FORM_KEY = `reg_form_${eventId}`;
  const STEP_KEY = `reg_step_${eventId}`;

  const [form, setForm] = React.useState(() => {
    try {
      const saved = sessionStorage.getItem(FORM_KEY);
      return saved ? JSON.parse(saved) : {
        name: "", email: "", company: "", job_title: "",
        country: "", phone: "", city: "",
        primary_reason: "", categories_interest: "", specific_product_interest: "",
        visited_booth_last_year: null, had_meeting_last_year: null,
        is_existing_customer: null, actively_sourcing: null,
        purchase_timeline: null, wants_meeting: null, preferred_visit_day: null,
      };
    } catch { return {
      name: "", email: "", company: "", job_title: "",
      country: "", phone: "", city: "",
      primary_reason: "", categories_interest: "", specific_product_interest: "",
      visited_booth_last_year: null, had_meeting_last_year: null,
      is_existing_customer: null, actively_sourcing: null,
      purchase_timeline: null, wants_meeting: null, preferred_visit_day: null,
    }; }
  });

  // Restore step from sessionStorage
  React.useEffect(() => {
    try {
      const savedStep = sessionStorage.getItem(STEP_KEY);

      if (savedStep && step === 1) setStep(parseInt(savedStep));
    } catch {}
  }, []);

  // Persist form to sessionStorage on every change
  React.useEffect(() => {
    try { sessionStorage.setItem(FORM_KEY, JSON.stringify(form)); } catch {}
  }, [form]);

  // Persist step
  React.useEffect(() => {
    try { sessionStorage.setItem(STEP_KEY, String(step)); } catch {}
  }, [step]);

  // Fetch event info on mount — cache in sessionStorage to avoid re-fetching
  React.useEffect(() => {
    const cacheKey = `reg_info_${eventId}`;
    const cached = sessionStorage.getItem(cacheKey);
    if (cached) {
      try { setEventInfo(JSON.parse(cached)); setLoading(false); return; } catch {}
    }
    fetch(`/api/v1/audience/register/${eventId}/info`)
      .then(r => r.json())
      .then(data => {
        setEventInfo(data);
        sessionStorage.setItem(cacheKey, JSON.stringify(data));
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [eventId]);

  const upd = (k, v) => {
    setForm(f => ({ ...f, [k]: v }));
    setFErrors(fe => ({ ...fe, [k]: null }));
  };

  const iS = {
    width: "100%", padding: "10px 13px",
    border: "1px solid #E2E8F0", borderRadius: 8,
    fontSize: 13, fontFamily: F, boxSizing: "border-box",
    outline: "none", background: "#fff", color: "#0F172A",
  };
  const lS = {
    display: "block", fontSize: 11, fontWeight: 600,
    color: "#64748B", marginBottom: 5,
    textTransform: "uppercase", letterSpacing: .06,
  };

  const validateStep1 = () => {
    const errs = {};
    if (!form.name.trim())    errs.name    = "Name is required";
    if (/\d/.test(form.name)) errs.name    = "Name should not contain numbers";
    const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;
    if (!emailRe.test(form.email))    errs.email   = "Enter a valid email address";
    if (emailStatus === "registered") errs.email   = "This email is already registered for this event";
    if (!form.company.trim()) errs.company = "Company is required";
    if (!form.job_title.trim()) errs.job_title = "Job title is required";
    setFErrors(errs);
    return Object.keys(errs).length === 0;
  };

  const handleSubmit = async () => {
    setSaving(true); setError("");
    try {
      const res = await fetch(`/api/v1/audience/register/${eventId}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (res.ok) {
        if (data.already_registered) {
          // Already registered — show friendly message on step 3
          setResult({...data, already_registered: true});
          setStep(3);
        } else {
          setResult(data);
          setStep(3);
        }
        // Clear saved form data after successful submission
        try {
          sessionStorage.removeItem(`reg_form_${eventId}`);
          sessionStorage.removeItem(`reg_step_${eventId}`);
          sessionStorage.removeItem(`reg_info_${eventId}`);
        } catch {}
      } else {
        setError(data.detail || "Registration failed. Please try again.");
      }
    } catch(e) {
      setError("Network error. Please try again.");
    } finally {
      setSaving(false);
    }
  };

  const YesNo = ({ label, field, extra }) => (
    <div style={{ marginBottom: 18 }}>
      <label style={lS}>{label}</label>
      <div style={{ display: "flex", gap: 10, marginTop: 6 }}>
        {[["yes", "✓  Yes", "#16A34A", "#F0FDF4", "#86EFAC"],
          ["no",  "✗  No",  "#DC2626", "#FEF2F2", "#FECACA"],
          ...(extra || [])
        ].map(([val, lbl, tc, bg, bc]) => (
          <button key={val} onClick={() => upd(field, val === form[field] ? null : val)}
            style={{
              flex: 1, padding: "10px 8px", borderRadius: 8,
              border: `2px solid ${form[field] === val ? bc : "#E2E8F0"}`,
              background: form[field] === val ? bg : "#fff",
              color: form[field] === val ? tc : "#64748B",
              fontFamily: F, fontSize: 12, fontWeight: 700, cursor: "pointer",
            }}>
            {lbl}
          </button>
        ))}
      </div>
    </div>
  );

  if (loading) return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: F, background: "#F8FAFC" }}>
      <div style={{ textAlign: "center" }}>
        <div style={{ width: 36, height: 36, border: "3px solid #E2E8F0", borderTopColor: navy, borderRadius: "50%", animation: "spin 1s linear infinite", margin: "0 auto 12px" }}/>
        <p style={{ color: "#64748B", fontSize: 14 }}>Loading event details…</p>
      </div>
    </div>
  );

  if (!eventInfo) return (
    <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: F, background: "#F8FAFC" }}>
      <div style={{ textAlign: "center" }}>
        <div style={{ fontSize: 48, marginBottom: 16 }}>⚠️</div>
        <h2 style={{ fontSize: 20, fontWeight: 700, color: navy }}>Event not found</h2>
        <p style={{ color: "#64748B" }}>This registration link may be invalid or expired.</p>
      </div>
    </div>
  );

  return (
    <div style={{ minHeight: "100vh", background: "#F8FAFC", fontFamily: F }}>
      {/* Header */}
      <div style={{ background: `linear-gradient(135deg, ${navy} 0%, #1A2A5E 100%)`, padding: "24px 24px 32px" }}>
        <div style={{ maxWidth: 560, margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 20 }}>
            <img src="/Fingoh_White.png" alt="Fingoh" style={{ height: 24 }} onError={e => e.target.style.display = "none"}/>
          </div>
          <h1 style={{ color: "#fff", fontSize: 22, fontWeight: 800, margin: "0 0 6px", letterSpacing: "-0.02em" }}>
            {eventInfo.company}
          </h1>
          <p style={{ color: "rgba(255,255,255,0.65)", fontSize: 13, margin: "0 0 4px" }}>
            {eventInfo.name} · {eventInfo.venue}
          </p>
          <p style={{ color: "rgba(255,255,255,0.5)", fontSize: 12, margin: 0 }}>
            {eventInfo.date_from} – {eventInfo.date_to}
          </p>

          {/* Progress steps */}
          {step < 3 && (
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 20 }}>
              {[["1", "Your Details"], ["2", "Visit Intent"]].map(([n, label], i) => {
                const active = step === i + 1;
                const done   = step > i + 1;
                return (
                  <React.Fragment key={n}>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <div style={{
                        width: 24, height: 24, borderRadius: "50%",
                        background: done ? "#16A34A" : active ? "#fff" : "rgba(255,255,255,0.2)",
                        color: done ? "#fff" : active ? navy : "rgba(255,255,255,0.5)",
                        display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 11, fontWeight: 700, flexShrink: 0,
                      }}>
                        {done ? "✓" : n}
                      </div>
                      <span style={{ fontSize: 11, color: active ? "#fff" : "rgba(255,255,255,0.5)", fontWeight: active ? 600 : 400 }}>
                        {label}
                      </span>
                    </div>
                    {i < 1 && <div style={{ flex: 1, height: 1, background: "rgba(255,255,255,0.2)" }}/>}
                  </React.Fragment>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Form */}
      <div style={{ maxWidth: 560, margin: "0 auto", padding: "24px 16px 48px" }}>

        {/* ── Step 1: Details ── */}
        {step === 1 && (
          <div style={{ background: "#fff", borderRadius: 14, padding: 24, boxShadow: "0 1px 4px rgba(0,0,0,0.06)", border: "1px solid #E2E8F0" }}>
            <h2 style={{ fontSize: 16, fontWeight: 700, color: navy, margin: "0 0 4px" }}>Your details</h2>
            <p style={{ fontSize: 12, color: "#64748B", margin: "0 0 20px" }}>Tell us about yourself so we can personalise your visit experience.</p>

            {error && <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", borderRadius: 8, padding: "10px 14px", fontSize: 12, color: "#DC2626", marginBottom: 16 }}>{error}</div>}

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 14 }}>
              <div style={{ gridColumn: "span 2" }}>
                <label style={lS}>Full name *</label>
                <input value={form.name} onChange={e => upd("name", e.target.value)}
                  placeholder="e.g. Ravi Kumar"
                  style={{ ...iS, borderColor: fErrors.name ? "#DC2626" : "#E2E8F0" }}/>
                {fErrors.name && <p style={{ color: "#DC2626", fontSize: 11, margin: "3px 0 0" }}>{fErrors.name}</p>}
              </div>
              <div style={{ gridColumn: "span 2" }}>
                <label style={lS}>Work email *</label>
                <div style={{ position: "relative" }}>
                  <input type="email" value={form.email}
                    onChange={e => { upd("email", e.target.value); setEmailStatus(null); setFErrors(fe=>({...fe,email:null})); }}
                    onBlur={e => checkEmail(e.target.value)}
                    placeholder="e.g. ravi@tatamotors.com"
                    style={{ ...iS, borderColor: fErrors.email ? "#DC2626" : emailStatus === "new" ? "#16A34A" : "#E2E8F0", paddingRight: emailChecking ? 36 : 13 }}/>
                  {emailChecking && (
                    <div style={{ position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)", width: 14, height: 14, border: "2px solid #E2E8F0", borderTopColor: "#3B82F6", borderRadius: "50%", animation: "spin 0.8s linear infinite" }}/>
                  )}
                </div>
                {fErrors.email && <p style={{ color: "#DC2626", fontSize: 11, margin: "3px 0 0" }}>⚠ {fErrors.email}</p>}
                {emailStatus === "new" && !fErrors.email && <p style={{ color: "#16A34A", fontSize: 11, margin: "3px 0 0" }}>✓ Email verified — not yet registered</p>}
              </div>
              <div style={{ gridColumn: "span 2" }}>
                <label style={lS}>Company *</label>
                <input value={form.company} onChange={e => upd("company", e.target.value)}
                  placeholder="e.g. Tata Motors"
                  style={{ ...iS, borderColor: fErrors.company ? "#DC2626" : "#E2E8F0" }}/>
                {fErrors.company && <p style={{ color: "#DC2626", fontSize: 11, margin: "3px 0 0" }}>{fErrors.company}</p>}
              </div>
              <div style={{ gridColumn: "span 2" }}>
                <label style={lS}>Job title *</label>
                <input value={form.job_title} onChange={e => upd("job_title", e.target.value)}
                  placeholder="e.g. Head of Electronics Sourcing"
                  style={{ ...iS, borderColor: fErrors.job_title ? "#DC2626" : "#E2E8F0" }}/>
                {fErrors.job_title && <p style={{ color: "#DC2626", fontSize: 11, margin: "3px 0 0" }}>{fErrors.job_title}</p>}
              </div>
              <div>
                <label style={lS}>Country</label>
                <input value={form.country} onChange={e => upd("country", e.target.value)} placeholder="e.g. India" style={iS}/>
              </div>
              <div>
                <label style={lS}>City</label>
                <input value={form.city} onChange={e => upd("city", e.target.value)} placeholder="e.g. Mumbai" style={iS}/>
              </div>
              <div style={{ gridColumn: "span 2" }}>
                <label style={lS}>Phone</label>
                <input value={form.phone} onChange={e => upd("phone", e.target.value)} placeholder="e.g. +91 98765 43210" style={iS}/>
              </div>
            </div>

            {/* Primary reason */}
            <div style={{ marginBottom: 14 }}>
              <label style={lS}>Primary reason for visiting</label>
              <select value={form.primary_reason} onChange={e => upd("primary_reason", e.target.value)}
                style={{ ...iS, appearance: "none" }}>
                <option value="">Select reason</option>
                {["Sourcing new suppliers", "Evaluating technology", "Market research",
                  "Networking", "Meeting existing suppliers", "Product evaluation", "Other"].map(r =>
                  <option key={r} value={r}>{r}</option>
                )}
              </select>
            </div>

            {/* Categories */}
            {eventInfo.categories?.length > 0 && (
              <div style={{ marginBottom: 14 }}>
                <label style={lS}>Product categories of interest</label>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 6 }}>
                  {eventInfo.categories.map(cat => {
                    const sel = (form.categories_interest || "").includes(cat);
                    return (
                      <button key={cat} onClick={() => {
                        const cats = form.categories_interest ? form.categories_interest.split(",").map(s => s.trim()).filter(Boolean) : [];
                        const next = sel ? cats.filter(c => c !== cat) : [...cats, cat];
                        upd("categories_interest", next.join(", "));
                      }} style={{
                        padding: "6px 12px", borderRadius: 99, fontSize: 11, fontWeight: sel ? 700 : 400,
                        border: `1.5px solid ${sel ? navy : "#E2E8F0"}`,
                        background: sel ? navy : "#fff", color: sel ? "#fff" : "#64748B",
                        cursor: "pointer", fontFamily: F,
                      }}>
                        {cat}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}

            <button onClick={() => { if (validateStep1()) { setStep(2); window.scrollTo(0, 0); } }}
              style={{ width: "100%", padding: "12px 0", background: navy, color: "#fff", border: "none", borderRadius: 9, fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: F, marginTop: 8 }}>
              Next — Tell us about your visit →
            </button>
          </div>
        )}

        {/* ── Step 2: Intent questions ── */}
        {step === 2 && (
          <div style={{ background: "#fff", borderRadius: 14, padding: 24, boxShadow: "0 1px 4px rgba(0,0,0,0.06)", border: "1px solid #E2E8F0" }}>
            <h2 style={{ fontSize: 16, fontWeight: 700, color: navy, margin: "0 0 4px" }}>Your visit intent</h2>
            <p style={{ fontSize: 12, color: "#64748B", margin: "0 0 20px" }}>Help {eventInfo.company} prepare for your visit. This takes 60 seconds.</p>

            {error && <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", borderRadius: 8, padding: "10px 14px", fontSize: 12, color: "#DC2626", marginBottom: 16 }}>{error}</div>}

            <YesNo label={`Did you visit ${eventInfo.company}'s booth at a previous edition?`} field="visited_booth_last_year"/>
            <YesNo label={`Did you have a meeting with ${eventInfo.company}'s team last year?`} field="had_meeting_last_year"/>
            <YesNo label="Are you an existing customer?" field="is_existing_customer"
              extra={[["evaluating", "🔄  Evaluating", "#D97706", "#FFFBEB", "#FCD34D"]]}/>
            <YesNo label="Are you actively looking to source or procure?" field="actively_sourcing"/>

            {/* Purchase timeline */}
            <div style={{ marginBottom: 18 }}>
              <label style={lS}>Purchase / decision timeline</label>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 6 }}>
                {[["<3months", "< 3 months"], ["3-6months", "3–6 months"], ["6-12months", "6–12 months"], ["no_plan", "No immediate plan"]].map(([val, lbl]) => (
                  <button key={val} onClick={() => upd("purchase_timeline", val === form.purchase_timeline ? null : val)}
                    style={{
                      padding: "10px 8px", borderRadius: 8, fontSize: 12, fontWeight: form.purchase_timeline === val ? 700 : 400,
                      border: `2px solid ${form.purchase_timeline === val ? navy : "#E2E8F0"}`,
                      background: form.purchase_timeline === val ? navy : "#fff",
                      color: form.purchase_timeline === val ? "#fff" : "#64748B",
                      cursor: "pointer", fontFamily: F,
                    }}>
                    {lbl}
                  </button>
                ))}
              </div>
            </div>

            {/* Preferred visit day */}
            {eventInfo.date_from && eventInfo.date_to && (
              <div style={{ marginBottom: 18 }}>
                <label style={lS}>Preferred visit day</label>
                <div style={{ display: "flex", gap: 8, marginTop: 6, flexWrap: "wrap" }}>
                  {(() => {
                    const days = [];
                    const start = new Date(eventInfo.date_from);
                    const end   = new Date(eventInfo.date_to);
                    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
                      days.push(new Date(d).toISOString().split("T")[0]);
                    }
                    return days.map(day => (
                      <button key={day} onClick={() => upd("preferred_visit_day", day === form.preferred_visit_day ? null : day)}
                        style={{
                          padding: "8px 14px", borderRadius: 8, fontSize: 12, fontWeight: form.preferred_visit_day === day ? 700 : 400,
                          border: `2px solid ${form.preferred_visit_day === day ? navy : "#E2E8F0"}`,
                          background: form.preferred_visit_day === day ? navy : "#fff",
                          color: form.preferred_visit_day === day ? "#fff" : "#64748B",
                          cursor: "pointer", fontFamily: F,
                        }}>
                        {new Date(day).toLocaleDateString("en-IN", { weekday: "short", day: "numeric", month: "short" })}
                      </button>
                    ));
                  })()}
                </div>
              </div>
            )}

            {/* Specific product interest */}
            <div style={{ marginBottom: 18 }}>
              <label style={lS}>Specific product or solution you're interested in</label>
              <input value={form.specific_product_interest || ""} onChange={e => upd("specific_product_interest", e.target.value)}
                placeholder={`e.g. ${eventInfo.product || "specific product area"}`}
                style={iS}/>
            </div>

            <YesNo label={`Would you like to schedule a dedicated meeting with ${eventInfo.company}?`} field="wants_meeting"/>

            <div style={{ display: "flex", gap: 10, marginTop: 8 }}>
              <button onClick={() => setStep(1)}
                style={{ flex: 1, padding: "11px 0", background: "#fff", color: "#64748B", border: "1px solid #E2E8F0", borderRadius: 9, fontSize: 13, fontWeight: 600, cursor: "pointer", fontFamily: F }}>
                ← Back
              </button>
              <button onClick={handleSubmit} disabled={saving}
                style={{ flex: 2, padding: "11px 0", background: saving ? "#CBD5E1" : "#16A34A", color: "#fff", border: "none", borderRadius: 9, fontSize: 13, fontWeight: 700, cursor: saving ? "not-allowed" : "pointer", fontFamily: F, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
                {saving ? <><div style={{ width: 14, height: 14, border: "2px solid rgba(255,255,255,0.3)", borderTop: "2px solid #fff", borderRadius: "50%", animation: "spin 0.8s linear infinite" }}/>Registering…</> : "✓ Complete registration"}
              </button>
            </div>
          </div>
        )}

        {/* ── Step 3: Success ── */}
        {step === 3 && result && (
          <div style={{ background: "#fff", borderRadius: 14, padding: 32, boxShadow: "0 1px 4px rgba(0,0,0,0.06)", border: "1px solid #E2E8F0", textAlign: "center" }}>
            <div style={{ width: 64, height: 64, borderRadius: "50%", background: result.already_registered ? "#FEF9C3" : "#DCFCE7", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, margin: "0 auto 16px" }}>
              {result.already_registered ? "ℹ️" : "✓"}
            </div>
            <h2 style={{ fontSize: 20, fontWeight: 800, color: navy, margin: "0 0 8px" }}>
              {result.already_registered ? "Already registered!" : "You're registered!"}
            </h2>
            <p style={{ fontSize: 13, color: "#64748B", margin: "0 0 20px", lineHeight: 1.6 }}>
              {result.message}
            </p>
            {result.wants_meeting === "yes" && (
              <div style={{ background: "#EFF6FF", border: "1px solid #BFDBFE", borderRadius: 10, padding: "12px 16px", marginBottom: 16 }}>
                <p style={{ fontSize: 12, color: "#1D4ED8", margin: 0, fontWeight: 600 }}>
                  📅 Meeting request noted — {result.exhibitor} will reach out to confirm a time
                </p>
              </div>
            )}
            <div style={{ background: "#F8FAFC", border: "1px solid #E2E8F0", borderRadius: 10, padding: "12px 16px", marginBottom: 16 }}>
              <p style={{ fontSize: 11, color: "#94A3B8", margin: 0 }}>
                Powered by <strong style={{ color: navy }}>Fingoh</strong> · Event Intelligence Platform
              </p>
            </div>
            <button onClick={() => {
              try {
                sessionStorage.removeItem(`reg_form_${eventId}`);
                sessionStorage.removeItem(`reg_step_${eventId}`);
              } catch {}
              setStep(1);
              setResult(null);
              setForm({
                name: "", email: "", company: "", job_title: "",
                country: "", phone: "", city: "",
                primary_reason: "", categories_interest: "", specific_product_interest: "",
                visited_booth_last_year: null, had_meeting_last_year: null,
                is_existing_customer: null, actively_sourcing: null,
                purchase_timeline: null, wants_meeting: null, preferred_visit_day: null,
              });
            }} style={{ width: "100%", padding: "10px 0", background: "#fff", color: navy, border: `1px solid ${navy}`, borderRadius: 9, fontSize: 12, fontWeight: 600, cursor: "pointer", fontFamily: F }}>
              Register another person
            </button>
          </div>
        )}
      </div>
    </div>
  );
}


  // Meeting response page — public, no auth needed
  if (window.location.pathname === "/meeting") {
    const params = new URLSearchParams(window.location.search);
    const token  = params.get("token");
    return <MeetingResponsePage token={token}/>;
  }

  if (authLoading) return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"DM Sans, sans-serif",fontSize:14,color:"#64748B"}}>
      Loading...
    </div>
  )
  if(screen==="login")
    return <LoginScreen onLogin={()=>setScreen("events")}/>;
  if(screen==="events")
    return <EventHome
      profile={profile}
      onLaunch={cfg=>{setEx(cfg);setScreen("audience");}}
      onCreateEvent={()=>setScreen("create-event")}/>;

  if(screen==="create-event")
    return <CreateEventWizard
      onBack={()=>setScreen("events")}
      onCreated={cfg=>{
      setEx(cfg);
      setScreen("events");
    }}/>;

  return (
    <>
      <NavShell screen={screen} onNav={s=>{setScreen(s);setSelP(null);}} ex={ex} onAgent={()=>setAgentOpen(true)} agentCount={agentQueueCount} onBackToEvents={()=>{setScreen("events");setSelP(null);}} profile={profile}>
        {screen==="audience"    && <AudienceUpload key={screen} ex={ex} onNext={()=>setScreen("iei")}/>}
        {screen==="iei"         && <IEIAnalysis ex={ex}/>}
        {screen==="meetings"    && <MeetingsScreen ex={ex}/>}
        {screen==="live"        && !selP && <LiveDashboard ex={ex} onParticipant={p=>setSelP(p)} onStaff={()=>setScreen("staff")}/>}
        {screen==="live"        && selP  && <ParticipantDetail p={selP} onBack={()=>setSelP(null)}/>}
        {screen==="outcomes"    && <OutcomesDashboard ex={ex}/>}
        {screen==="export"      && <LeadExport ex={ex}/>}
        {screen==="agent"       && <AgentPage ex={ex} onQueueLoaded={setAgentQueueCount}/>}
        {screen==="staff"       && <StaffApp ex={ex} verifyStaff={verifyStaff}/>}
        {screen==="event-setup" && <EventSetup ex={ex} onUpdate={setEx} onDelete={()=>{setEx(null);setScreen("events");}}/>}
      </NavShell>

    </>
  );
}
